window.PACTO.acts["reg-2014-223"]={"label": "REGOLAMENTO (UE) N. 223/2014 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 223/2014", "file": "ext-reg-2014-223.html", "external": true, "version": "consolidato 2024-03-01", "eurlex": "https://eur-lex.europa.eu/eli/reg/2014/223/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e finalità", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento istituisce, per il periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2014 e il 31 dicembre 2020, il Fondo per gli aiuti europei agli indigenti (il \"Fondo\") e definisce gli obiettivi del Fondo, l'ambito d'intervento del suo sostegno, le risorse finanziarie disponibili e la loro ripartizione per ciascun Stato membro, e fissa le norme necessarie a garantire l'efficacia e l'efficienza del Fondo.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"assistenza materiale di base\" : beni di consumo di base di valore limitato forniti alle persone indigenti per uso personale, ad esempio vestiario, calzature, prodotti per l'igiene, materiale scolastico e sacchi a pelo;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"persone indigenti\" : persone fisiche, singoli, famiglie e nuclei familiari o gruppi composti da tali persone, la cui necessità di assistenza è stata riconosciuta in base ai criteri oggettivi fissati dalle competenti autorità nazionali in consultazione con le parti interessate, evitando conflitti di interessi, o definiti dalle organizzazioni partner e approvati da dette autorità nazionali, che possono includere elementi tali da consentire di indirizzare il sostegno verso le persone indigenti in determinate aree geografiche;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">3)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"organizzazioni partner\" : gli organismi pubblici e/o le organizzazioni senza scopo di lucro che distribuiscono prodotti alimentari e/o forniscono assistenza materiale di base, ove applicabile, attuando altresì misure di accompagnamento, direttamente o attraverso altre organizzazioni partner, oppure che intraprendono attività direttamente finalizzate all'inclusione sociale delle persone indigenti, e le cui operazioni sono state selezionate dall'autorità di gestione a norma dell'articolo 32, paragrafo 3;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">4)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"programmi nazionali\" : qualsiasi programma avente, almeno in parte, gli stessi obiettivi del Fondo e attuato a livello nazionale, regionale o locale da organismi pubblici od organizzazioni senza scopo di lucro;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">5)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"programma operativo per la fornitura di prodotti alimentari e/o assistenza materiale di base\" (\"PO I\") : un programma operativo che sostiene la distribuzione di prodotti alimentari e/o la fornitura di assistenza materiale di base alle persone indigenti, associato se del caso a misure di accompagnamento e finalizzato ad alleviare l'esclusione sociale delle persone indigenti;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">6)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"programma operativo per l'inclusione sociale delle persone indigenti\" (\"PO II\") : un programma operativo a sostegno delle attività che non rientrano nelle misure attive per il mercato del lavoro, che prevede assistenza non finanziaria e non materiale ed è finalizzato all'inclusione sociale delle persone indigenti;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">7)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"operazione\" : un progetto, un contratto o un'azione selezionati dall'autorità di gestione del programma operativo in questione o sotto la sua responsabilità, che contribuisce alla realizzazione degli obiettivi del programma operativo cui si riferisce;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">8)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"operazione completata\" : un'operazione materialmente completata o pienamente realizzata e per la quale tutti i pagamenti previsti sono stati effettuati dai beneficiari e il sostegno del programma operativo corrispondente è stato erogato ai beneficiari;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">9)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"beneficiario\" : un organismo pubblico o privato responsabile dell'avvio o dell'avvio e dell'attuazione delle operazioni;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">10)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"destinatario finale\" : la persona o le persone indigenti che ricevono il sostegno di cui all'articolo 4 del presente regolamento;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">11)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"misure di accompagnamento\" : le attività svolte in aggiunta alla distribuzione di prodotti alimentari e/o alla fornitura di assistenza materiale di base al fine di alleviare l'esclusione sociale e/o di affrontare le emergenze sociali in modo più cosciente e sostenibile, ad esempio orientamenti su una dieta equilibrata e consulenza in materia di gestione finanziaria;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">12)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"spesa pubblica\" : qualsiasi contributo pubblico al finanziamento di operazioni proveniente dal bilancio di un'autorità pubblica nazionale, regionale o locale, dal bilancio dell'Unione destinato al Fondo, dal bilancio di un organismo di diritto pubblico o dal bilancio di associazioni di autorità pubbliche o di un organismo di diritto pubblico ai sensi dell'articolo 1, paragrafo 9, della direttiva 2004/18/CE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n);</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">13)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"organismo intermedio\" : ogni organismo pubblico o privato che agisce sotto la responsabilità di un'autorità di gestione o di certificazione o che svolge mansioni per conto di questa autorità in relazione alle operazioni attuate dai beneficiari;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">14)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"esercizio contabile\" : il periodo che va dal 1<span class=\"superscript\">o</span> luglio al 30 giugno, tranne per il primo esercizio del periodo di programmazione, relativamente al quale si intende il periodo che va dalla data di inizio dell'ammissibilità della spesa al 30 giugno 2015. Il periodo contabile finale va dal 1<span class=\"superscript\">o</span> luglio 2023 al 30 giugno 2024;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">15)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"esercizio finanziario\" : il periodo che va dal 1<span class=\"superscript\">o</span> gennaio al 31 dicembre;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">16)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"irregolarità\" : qualsiasi violazione del diritto dell'Unione o nazionale relativa alla sua applicazione, derivante da un'azione o un'omissione di un operatore economico coinvolto nell'attuazione del Fondo che abbia o possa avere come conseguenza un pregiudizio al bilancio dell'Unione mediante l'imputazione di spese indebite al bilancio dell'Unione;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">17)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"operatore economico\" : qualsiasi persona fisica o giuridica o altra entità che partecipa all'attuazione dell'intervento del Fondo, ad eccezione di uno Stato membro nell'esercizio delle sue prerogative di autorità pubblica;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">18)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"irregolarità sistemica\" : qualsiasi irregolarità che possa essere di natura ricorrente, con un'elevata probabilità di verificarsi in tipi simili di operazioni, che deriva da una grave carenza nel funzionamento efficace di un sistema di gestione e di controllo, compresa la mancata istituzione di procedure adeguate conformemente al presente regolamento;</p>\n</td>\n</tr>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">19)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">\"carenza grave nell'efficace funzionamento di un sistema di gestione e di controllo\" : una carenza per la quale risultano necessari miglioramenti sostanziali nel sistema, tali da esporre il Fondo a un rischio rilevante di irregolarità e la cui esistenza è incompatibile con una revisione contabile senza rilievi sul funzionamento del sistema di gestione e di controllo.</p>\n</td>\n</tr>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Obiettivi", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Fondo promuove la coesione sociale, rafforza l'inclusione sociale e concorre quindi in ultima analisi all'obiettivo di eliminare la povertà nell'Unione, contribuendo a conseguire l'obiettivo di ridurre di almeno 20 milioni il numero delle persone a rischio di povertà e di esclusione sociale a norma della strategia Europa 2020, e integra nel contempo i fondi strutturali. Il Fondo contribuisce al conseguimento dell'obiettivo specifico di alleviare le forme più gravi di povertà, prestando un'assistenza non finanziaria alle persone indigenti mediante prodotti alimentari e/o assistenza materiale di base nonché attività a favore dell'inclusione sociale finalizzate all'integrazione sociale delle persone indigenti.</div>\n</div>"], [null, "<p class=\"norm\">Tale obiettivo e i risultati dell'attuazione del Fondo sono valutati in termini sia qualitativi che quantitativi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Fondo integra le politiche nazionali sostenibili per l'eliminazione della povertà e per l'inclusione sociale, che rimangono responsabilità degli Stati membri.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Ambito di intervento", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Fondo sostiene programmi nazionali nell'ambito dei quali organizzazioni partner selezionate dagli Stati membri distribuiscono alle persone indigenti prodotti alimentari e/o assistenza materiale di base.</div>\n</div>"], [null, "<p class=\"norm\">Al fine di aumentare e diversificare la fornitura di prodotti alimentari alle persone indigenti nonché di ridurre ed evitare lo spreco di alimenti, il Fondo può sostenere attività legate alla raccolta, al trasporto, al magazzinaggio e alla distribuzione di donazioni di prodotti alimentari.</p>"], [null, "<p class=\"norm\">Il Fondo può altresì finanziare misure di accompagnamento che integrano la fornitura di prodotti alimentari e/o assistenza materiale di base.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Fondo sostiene le attività che contribuiscono all'inclusione sociale delle persone indigenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Fondo promuove a livello dell'Unione l'apprendimento reciproco, il collegamento in rete e la diffusione delle buone prassi in materia di assistenza non finanziaria alle persone indigenti.</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Principi", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La parte di bilancio dell'Unione destinata al Fondo è eseguita nell'ambito della gestione concorrente tra gli Stati membri e la Commissione, in conformità dell'articolo 58, paragrafo 1, lettera b), del regolamento finanziario, fatta eccezione per l'assistenza tecnica su iniziativa della Commissione, che è fornita nell'ambito della gestione diretta a norma dell'articolo 58, paragrafo 1, lettera a), del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri provvedono, tenendo conto del contesto specifico di ciascuno Stato membro, affinché il sostegno del Fondo sia coerente con le pertinenti politiche e priorità dell'Unione e complementare agli altri strumenti dell'Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sostegno a titolo del Fondo è eseguito in stretta cooperazione fra la Commissione e gli Stati membri conformemente al principio di sussidiarietà.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e gli organismi da essi designati a tale scopo sono responsabili dell'attuazione dei programmi operativi e dello svolgimento dei rispettivi compiti ai sensi del presente regolamento in conformità al quadro istituzionale, giuridico e finanziario dello Stato membro e nel rispetto del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le modalità di esecuzione e di impiego del Fondo, in particolare le risorse finanziarie e amministrative richieste per la predisposizione di relazioni, la valutazione, la gestione e il controllo, tengono conto del principio di proporzionalità rispetto al livello del sostegno assegnato e della capacità amministrativa limitata delle organizzazioni le cui attività sono principalmente svolte da volontari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In funzione delle rispettive competenze e al fine di evitare doppi finanziamenti, la Commissione e gli Stati membri provvedono al coordinamento con il FSE e con altre politiche, strategie e strumenti pertinenti dell'Unione, in particolare le iniziative dell'Unione nel settore della sanità pubblica e della lotta agli sprechi alimentari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione, gli Stati membri e i beneficiari applicano il principio di sana gestione finanziaria di cui all'articolo 30 del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri provvedono ad assicurare l'efficacia del Fondo, in particolare tramite la sorveglianza, la predisposizione di relazioni e la valutazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione provvedono ad assicurare che i programmi operativi siano predisposti, programmati, attuati, monitorati e valutati, nel rispetto del principio di partenariato, nell'ambito delle consultazioni delle parti interessate in conformità del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri prendono provvedimenti per garantire l'efficacia del Fondo e svolgono i rispettivi ruoli in relazione al Fondo in modo da ridurre gli oneri amministrativi a carico dei beneficiari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri provvedono affinché la parità tra donne e uomini e l'integrazione della prospettiva di genere siano tenute in considerazione e promosse nel corso delle varie fasi della preparazione, della programmazione, della gestione ed attuazione, della sorveglianza e della valutazione del Fondo, nonché nelle campagne di informazione e di sensibilizzazione e nello scambio delle migliori prassi. La Commissione e gli Stati membri ricorrono a dati disaggregati per genere, ove disponibili.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione e gli Stati membri adottano le misure necessarie per prevenire qualsiasi discriminazione fondata su sesso, razza o origine etnica, religione o convinzioni personali, disabilità, età o orientamento sessuale ai fini dell'accesso al Fondo nonché a programmi e operazioni da esso sostenuti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Le operazioni sostenute dal Fondo sono conformi al diritto applicabile dell'Unione e nazionale relativo alla sua attuazione (il \"diritto applicabile\"). In particolare, il Fondo può essere impiegato solo per sostenere la distribuzione di prodotti alimentari o beni conformi al diritto dell'Unione in materia di sicurezza dei prodotti di consumo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e i beneficiari scelgono i prodotti alimentari e/o l'assistenza materiale di base secondo criteri obiettivi correlati alle esigenze delle persone indigenti. I criteri di selezione dei prodotti alimentari, e se del caso dei beni, tengono inoltre conto degli aspetti climatici e ambientali, in particolare in vista della riduzione degli sprechi alimentari. Ove opportuno, la scelta del tipo di prodotti alimentari da distribuire è effettuata tenendo conto del contributo da essi apportato nel garantire una dieta equilibrata alle persone indigenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">14.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri assicurano che gli aiuti forniti nel quadro del presente Fondo rispettino la dignità delle persone indigenti.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Risorse globali", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le risorse disponibili a titolo del Fondo per gli impegni di bilancio per il periodo 2014-2020 ammontano a 3 395 684 880  EUR, espresse in prezzi 2011, secondo la ripartizione annuale che figura nell'allegato II.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La dotazione del Fondo per ciascuno Stato membro per il periodo 2014-2020 è stabilita nell’allegato III, fatta eccezione per le risorse aggiuntive assegnate in risposta all’epidemia di COVID-19 di cui all’articolo 6 <span class=\"italics\">bis</span>. L’importo minimo destinato a ciascuno Stato membro è pari a 3 500 000  EUR per l’intero periodo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini della programmazione e della successiva imputazione al bilancio generale dell'Unione, l'importo delle risorse è indicizzato in ragione del 2 % annuo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo 0,35 % delle risorse globali è destinato all'assistenza tecnica su iniziativa della Commissione.</div>\n</div>"]]}, "6a": {"label": "Articolo 6 bis", "heading": "Risorse aggiuntive in risposta alla crisi determinata dall’epidemia di COVID-19", "anchor": "art_6a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ove lo Stato membro lo ritenga opportuno, le risorse di cui all’articolo 6, paragrafo 1, del presente regolamento sono incrementate in risposta alla crisi determinata dall’epidemia di COVID-19, conformemente all’articolo 92 <span class=\"italics\">ter</span>, paragrafo 5, settimo comma, del regolamento (UE) n. 1303/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n) e alle condizioni pertinenti stabilite da tale paragrafo. Le risorse aggiuntive costituiscono un’entrata con destinazione specifica esterna ai sensi dell’articolo 3, paragrafo 1, del regolamento (UE) 2020/2094 del Consiglio (\n<span class=\"superscript\">3</span>\n) e sono soggette all’articolo 3, paragrafi 3, 4, 7 e 9 del medesimo regolamento. Le risorse aggiuntive possono incidere sugli impegni di bilancio per gli anni 2021 e 2022.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 7, paragrafo 1, per i programmi operativi che beneficiano di risorse aggiuntive conformemente al paragrafo 1 del presente articolo il periodo termina il 31 dicembre 2022.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 38, primo comma, del presente regolamento, gli impegni di bilancio per le risorse aggiuntive per ciascun programma sono effettuati negli anni 2021 e 2022.</div>\n</div>"], [null, "<p class=\"norm\">In deroga all’articolo 59, paragrafo 1, del presente regolamento, gli impegni di bilancio per le risorse aggiuntive sono disimpegnati conformemente alle norme da seguire per la chiusura dei programmi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Oltre al prefinanziamento di cui all’articolo 44, paragrafo 1, la Commissione versa, a titolo di prefinanziamento, un importo pari all’11 % delle risorse aggiuntive assegnate per il 2021 a seguito della decisione della Commissione che approva la modifica di un programma per l’assegnazione delle risorse aggiuntive.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">In aggiunta al prefinanziamento iniziale di cui al primo comma, la Commissione versa, quale prefinanziamento iniziale aggiuntivo nel 2022, il 4 % delle risorse REACT-EU assegnate ai programmi per l'anno 2021. Per i programmi negli Stati membri che hanno registrato un livello di arrivi di persone dall'Ucraina superiore all'1 % rispetto alla loro popolazione nazionale tra il 24 febbraio 2022 e il 23 marzo 2022, detta percentuale è aumentata al 34 %.</p>"], [null, "<p class=\"modref\">\n▼M5\n</p>"], [null, "<p class=\"norm\">La liquidazione contabile dell'importo versato a titolo di prefinanziamento iniziale di cui al primo e al secondo comma è effettuata integralmente dalla Commissione al più tardi al momento della chiusura del programma operativo.</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 20, un tasso di cofinanziamento fino al 100 % può essere applicato alle risorse aggiuntive di cui al paragrafo 1 del presente articolo.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Programmi operativi", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro presenta alla Commissione, entro sei mesi dall'entrata in vigore del presente regolamento, un PO I e/o un PO II per il periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2014 e il 31 dicembre 2020.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un PO I stabilisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'identificazione e una motivazione della scelta della tipologia o delle tipologie di deprivazione materiale da considerare individuate, motivandone debitamente la scelta, nell'ambito del programma operativo e, per ogni tipologia di deprivazione materiale considerata, una descrizione delle principali caratteristiche della distribuzione di prodotti alimentari e/o della fornitura di assistenza materiale di base nonché, se del caso, delle misure di accompagnamento da prevedere, tenendo conto dei risultati della valutazione ex ante effettuata in conformità dell'articolo 16;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione del programma o dei programmi nazionali corrispondenti per ciascun tipo di deprivazione materiale considerato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione del meccanismo per determinare i criteri di ammissibilità delle persone indigenti differenziati, se necessario, per tipo di deprivazione materiale considerato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri di selezione delle operazioni e una descrizione del meccanismo di selezione differenziati, se necessario, per tipo di deprivazione materiale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri di selezione delle organizzazioni partner differenziati, se necessario, per tipo di deprivazione materiale considerato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione del meccanismo utilizzato per provvedere alla complementarità con il FSE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un piano di finanziamento contenente una tabella che specifichi, per l'intero periodo di programmazione, l'importo della dotazione finanziaria complessiva prevista per il sostegno del programma operativo, suddiviso indicativamente per tipo di deprivazione materiale considerato, nonché le corrispondenti misure di accompagnamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un PO II stabilisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una strategia relativa al contributo del programma alla promozione della coesione sociale e alla riduzione della povertà, conformemente alla strategia Europa 2020, inclusa una giustificazione della scelta della priorità di intervento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi specifici del programma operativo sulla base dell'individuazione delle esigenze nazionali, tenendo conto dei risultati della valutazione ex ante effettuata in conformità dell'articolo 16. La valutazione ex ante è presentata alla Commissione contemporaneamente al programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un piano di finanziamento contenente una tabella che specifichi, per l'intero periodo di programmazione, l'importo della dotazione finanziaria complessiva prevista per il sostegno del programma operativo, suddiviso indicativamente per tipo di azione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'individuazione delle persone indigenti destinatarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli indicatori finanziari relativi alla corrispondente spesa assegnata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i risultati previsti per gli obiettivi specifici nonché i corrispondenti indicatori di realizzazione e di risultato specifici a ciascun programma, con un valore di riferimento e un valore obiettivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione della tipologia e degli esempi delle azioni da sostenere e il loro contributo atteso agli obiettivi specifici di cui alla lettera b), compresi i principi guida per la selezione delle operazioni e, se del caso, l'individuazione dei tipi di beneficiari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione del meccanismo utilizzato per garantire la complementarità con il FSE ed evitare sovrapposizioni e doppi finanziamenti tra le operazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni programma operativo stabilisce inoltre:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'identificazione dell'autorità di gestione, eventualmente dell'autorità di certificazione, dell'autorità di audit e dell'organismo al quale la Commissione effettua pagamenti nonché una descrizione della procedura di sorveglianza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione delle misure adottate per associare tutte le parti interessate e, se del caso, le autorità regionali, locali e altre autorità pubbliche competenti nella preparazione del programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione dell'utilizzo previsto dell'assistenza tecnica di cui all'articolo 27, paragrafo 4, comprese le azioni intese a rafforzare la capacità amministrativa dei beneficiari ai fini dell'attuazione del programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un piano di finanziamento contenente una tabella che specifichi, per ciascun anno, in conformità dell'articolo 20, l'importo della dotazione finanziaria prevista a titolo del Fondo e del cofinanziamento di cui all'articolo 20.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le organizzazioni partner di cui all'articolo 7, paragrafo 2, lettera e), che distribuiscono direttamente i prodotti alimentari e/o l'assistenza materiale di base svolgono esse stesse o in cooperazione con altre organizzazioni, le attività che consistono, se del caso, nel reindirizzamento ai servizi competenti, che integrano la prestazione di assistenza materiale e mirano all'inclusione sociale delle persone indigenti, indipendentemente dal fatto che le attività stesse siano finanziate dal Fondo. Tuttavia, il primo comma non si applica qualora i prodotti alimentari e/o l'assistenza materiale di base siano forniti esclusivamente a bambini indigenti presso strutture di assistenza all'infanzia o strutture analoghe.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri o un'autorità da essi designata redigono i programmi operativi. Essi cooperano con tutte le parti interessate nonché, laddove opportuno, con le competenti autorità regionali, locali e altre autorità pubbliche. Gli Stati membri garantiscono che i programmi operativi siano strettamente legati alle politiche nazionali di inclusione sociale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri elaborano i programmi operativi secondo gli opportuni modelli di cui all'allegato I.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Adozione dei programmi operativi", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione valuta la coerenza di ogni programma operativo con il presente regolamento e il relativo contributo agli obiettivi del Fondo tenendo conto della valutazione ex ante effettuata in conformità dell'articolo 16. La Commissione garantisce l'assenza di sovrapposizioni con i programmi operativi finanziati dal FSE nello Stato membro interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può formulare osservazioni entro tre mesi dalla data di presentazione del programma operativo. Lo Stato membro fornisce alla Commissione tutte le informazioni supplementari necessarie e, se del caso, rivede il programma operativo proposto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ove siano state prese adeguatamente in considerazione tutte le sue osservazioni formulate a norma del paragrafo 2, la Commissione approva ciascun programma operativo mediante atti di esecuzione entro sei mesi dalla sua presentazione da parte dello Stato membro.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Modifiche dei programmi operativi", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può presentare una richiesta di modifica di un programma operativo. La richiesta è corredata del programma operativo riveduto e della motivazione della modifica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione valuta le informazioni presentate a norma del paragrafo 1, tenendo conto della motivazione fornita dallo Stato membro e può formulare osservazioni al riguardo; in tal caso lo Stato membro fornisce alla Commissione tutte le informazioni supplementari necessarie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione approva, mediante atti di esecuzione, la modifica di un programma operativo entro quattro mesi dalla sua presentazione da parte dello Stato membro, purché siano state prese adeguatamente in considerazione tutte le osservazioni della Commissione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I paragrafi 1, 2 e 3 non si applicano ai fini della modifica di elementi di un programma operativo che rientrano rispettivamente nelle sottosezioni 3.5 e 3.6 e nella sezione 4 dei modelli di programma operativo di cui all’allegato I, o degli elementi di cui all’articolo 7, paragrafo 2, lettere da a) a e) e g), qualora tale modifica sia effettuata in conseguenza della crisi dovuta all’epidemia di COVID-19.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">Gli Stati membri comunicano alla Commissione qualsiasi decisione di modifica degli elementi di cui al primo comma entro un mese dalla data della decisione. La decisione indica la data della sua entrata in vigore, che non è anteriore alla data della sua adozione.</p>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<p class=\"norm\">Il primo e il secondo comma si applicano anche ai fini della modifica di elementi di un programma operativo per far fronte alle sfide migratorie in seguito all’aggressione militare da parte della Federazione russa.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "10": {"label": "Articolo 10", "heading": "Scambio di buone prassi", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">La Commissione facilita, anche per mezzo di un sito internet, lo scambio di esperienze, lo sviluppo di capacità, il collegamento in rete nonché la diffusione dei risultati pertinenti nell'ambito dell'assistenza non finanziaria alle persone indigenti.</p>"], [null, "<p class=\"norm\">Le organizzazioni pertinenti che non ricorrono al Fondo possono altresì essere incluse.</p>"], [null, "<p class=\"norm\">Almeno una volta all'anno la Commissione consulta inoltre le organizzazioni che rappresentano le organizzazioni partner a livello di Unione in merito al sostegno apportato dal Fondo e, in seguito a tale consultazione, riferisce quindi al Parlamento europeo e al Consiglio in tempo debito.</p>"], [null, "<p class=\"norm\">La Commissione facilita altresì la diffusione on-line dei risultati pertinenti, delle relazioni e delle informazioni riguardanti il Fondo.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Comitato di sorveglianza di un PO II", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro tre mesi dalla data di notifica allo Stato membro della decisione di adozione di un PO II, lo Stato membro istituisce o nomina un comitato, conformemente al suo quadro istituzionale, giuridico e finanziario, d'intesa con l'autorità di gestione, per sorvegliare sull'attuazione del programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun comitato di sorveglianza stabilisce e adotta il proprio regolamento interno in conformità del quadro istituzionale, giuridico e finanziario dello Stato membro interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La composizione del comitato di sorveglianza è decisa dallo Stato membro, purché sia composto da rappresentanti delle autorità competenti dello Stato membro, degli organismi intermedi e di tutte le parti interessate nonché, se del caso, da rappresentanti delle autorità regionali, locali e altre autorità pubbliche competenti. I rappresentanti delle autorità regionali, locali e altre autorità pubbliche competenti nonché delle parti interessate ricevono delega per far parte del comitato di sorveglianza dalle rispettive organizzazioni attraverso procedure trasparenti. Ciascun membro del comitato di sorveglianza può avere diritto di voto. L'elenco dei membri del comitato di sorveglianza è reso pubblico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione partecipa ai lavori del comitato di sorveglianza a titolo consultivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il comitato di sorveglianza è presieduto da un rappresentante dello Stato membro o dell'autorità di gestione.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Funzioni del comitato di sorveglianza del PO II", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il comitato di sorveglianza si riunisce almeno una volta all'anno per valutare l'attuazione del programma e i progressi compiuti nel conseguimento dei suoi obiettivi specifici. A tale proposito, tiene conto dei dati finanziari e degli indicatori comuni e specifici del programma, ivi compresi i cambiamenti nel valore degli indicatori di risultato e i progressi verso target quantificati, nonché se del caso dei risultati delle analisi qualitative.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il comitato di sorveglianza esamina tutti gli aspetti che incidono sui risultati del programma, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nella realizzazione degli obiettivi specifici del programma operativo sulla base dei documenti presentati dall'autorità di gestione, incluse le conclusioni della valutazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'attuazione delle azioni di informazione e comunicazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni che considerano e promuovono la parità tra uomini e donne, le pari opportunità e la non discriminazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il comitato di sorveglianza esamina e approva:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la metodologia e i criteri utilizzati per la selezione delle operazioni, in linea con i principi guida di cui all'articolo 7, paragrafo 3, lettera f);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le relazioni di attuazione annuali e finali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuali proposte di modifiche al programma operativo presentate dall'autorità di gestione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il comitato di sorveglianza può formulare osservazioni all'autorità di gestione in merito all'attuazione e alla valutazione del programma.</div>\n</div>"], [null, "<p class=\"norm\">Il comitato di sorveglianza controlla le azioni intraprese a seguito delle stesse.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Relazioni di attuazione e indicatori", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Dal 2015 al 2023 gli Stati membri trasmettono alla Commissione, entro il 30 giugno di ogni anno, una relazione annuale sul programma operativo attuato nel precedente esercizio finanziario.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">In deroga al primo comma, la scadenza del termine per la trasmissione della relazione di attuazione annuale per l’esercizio 2019 è fissata al 30 settembre 2020.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri elaborano la relazione di attuazione annuale conformemente all'atto delegato di cui al paragrafo 6, compreso l'elenco di indicatori comuni nonché, per i programmi operativi per l'inclusione sociale, l'elenco degli indicatori specifici per il programma.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri consultano le parti interessate, evitando i conflitti di interessi, in merito alle relazioni di attuazione del PO I. Una sintesi delle osservazioni di tali parti interessate è allegata alla relazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le relazioni di attuazione annuali si considerano ricevibili se contengono tutte le informazioni richieste conformemente all'atto delegato di cui al paragrafo 6. La Commissione comunica allo Stato membro interessato se la relazione di attuazione annuale non è ricevibile entro 15 giorni lavorativi dal ricevimento della stessa. Ove la Commissione non abbia informato lo Stato membro entro il termine stabilito, la relazione è considerata ricevibile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione esamina la relazione di attuazione annuale e trasmette allo Stato membro le sue osservazioni entro due mesi dalla data di ricevimento della stessa.</div>\n</div>"], [null, "<p class=\"norm\">Ove la Commissione non esprima osservazioni allo Stato membro entro il termine stabilito, le relazioni si considerano approvate.</p>"], [null, "<p class=\"modref\">\n▼M6\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Lo Stato membro presenta una relazione finale sull'attuazione del programma operativo, unitamente ai documenti di chiusura di cui all'articolo 52, entro e non oltre il 15 febbraio 2026.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo al contenuto delle relazioni di attuazione annuali e finali, compreso l'elenco degli indicatori comuni, entro il 17 luglio 2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione può inviare a uno Stato membro osservazioni relative all'attuazione del programma operativo. L'autorità di gestione informa entro tre mesi la Commissione delle misure correttive adottate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione provvede alla pubblicazione di una sintesi del contenuto di ogni relazione di attuazione annuale e finale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La Commissione presenta in tempo debito al Parlamento europeo e al Consiglio una sintesi delle relazioni di attuazione annuali e finali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">La procedura concernente le relazioni di attuazione non è eccessiva rispetto alle risorse stanziate e alla natura del sostegno e non provoca inutili oneri amministrativi.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Riunioni di riesame", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri si riuniscono ogni anno tra il 2014 e il 2023, salvo diverso accordo, per riesaminare i progressi compiuti nell'attuazione del programma operativo, tenuto conto della relazione di attuazione annuale e, se del caso, delle osservazioni della Commissione di cui all'articolo 13, paragrafo 7.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La riunione di riesame è presieduta dalla Commissione. Le parti interessate sono invitate a partecipare alle riunioni di riesame del PO I, fatta eccezione per le parti di tali riunioni in cui la loro partecipazione darebbe luogo a conflitti di interessi o a una violazione della riservatezza in relazione alle questioni in materia di audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro provvede affinché sia dato un seguito appropriato alle eventuali osservazioni della Commissione successivamente alla riunione di riesame e fa riferimento a tale seguito nella relazione di attuazione dell'esercizio o degli esercizi successivi, a seconda dei casi.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Disposizioni generali relative alla valutazione", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri forniscono le risorse necessarie allo svolgimento delle valutazioni e assicurano che siano predisposte procedure per la produzione e la raccolta dei dati necessari a tal fine, compresi i dati relativi agli indicatori comuni di cui all'articolo 13.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le valutazioni sono effettuate da esperti funzionalmente indipendenti dalle autorità responsabili dell'attuazione del programma operativo. Tutte le valutazioni sono rese pubbliche integralmente ma non comprendono in alcun caso informazioni che riguardano l'identità dei destinatari finali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le valutazioni non sono eccessive rispetto alle risorse stanziate o alla natura del sostegno e non provocano inutili oneri amministrativi.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Valutazione ex ante", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri effettuano una valutazione ex ante di ciascun programma operativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La valutazione ex ante è effettuata sotto la responsabilità dell'autorità competente per la preparazione del programma operativo ed è presentata alla Commissione contemporaneamente al programma operativo, unitamente a una sintesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le valutazioni ex ante di un PO I prendono in esame i seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo all'obiettivo dell'Unione di ridurre di almeno 20 milioni le persone che vivono in condizioni di povertà o che sono a rischio di povertà e di esclusione sociale entro il 2020, alla luce del tipo di deprivazione materiale considerata e tenuto conto delle circostanze nazionali in termini di povertà, esclusione sociale e deprivazione materiale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la coerenza interna del programma operativo proposto e il suo rapporto con altri strumenti finanziari pertinenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la coerenza dell'assegnazione delle risorse di bilancio con gli obiettivi del programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo delle realizzazioni previste ai risultati e, di conseguenza, agli obiettivi del Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il coinvolgimento delle parti interessate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'idoneità delle procedure per la sorveglianza del programma operativo e per la raccolta dei dati necessari per l'effettuazione delle valutazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le valutazioni ex ante di un PO II prendono in esame i seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo alla promozione della coesione sociale e alla riduzione della povertà, conformemente alla strategia Europa 2020, tenendo conto delle esigenze nazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la coerenza interna del programma proposto e il suo rapporto con altri strumenti pertinenti, in particolare il FSE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la coerenza dell'assegnazione delle risorse di bilancio con gli obiettivi del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la pertinenza e la chiarezza degli indicatori proposti specifici al programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in che modo le realizzazioni previste contribuiranno al conseguimento dei risultati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se i valori obiettivo quantificati relativi agli indicatori sono realistici, tenendo conto del sostegno previsto dal Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la motivazione della forma di sostegno proposta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'adeguatezza delle risorse umane e della capacità amministrativa per la gestione del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'idoneità delle procedure per la sorveglianza del programma e per la raccolta dei dati necessari per l'effettuazione delle valutazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'adeguatezza delle misure pianificate per promuovere le pari opportunità tra uomini e donne e impedire qualunque discriminazione.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Valutazione durante il periodo di programmazione", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette al Parlamento europeo e al Consiglio una valutazione intermedia del Fondo entro il 31 dicembre 2018.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può effettuare, di sua iniziativa, valutazioni dei programmi operativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Durante il periodo di programmazione l'autorità di gestione di un PO I può valutare l'efficacia e l'efficienza del programma operativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione di un PO I svolge un'indagine strutturata presso i destinatari finali nel 2017 e nel 2022, conformemente al modello adottato dalla Commissione. La Commissione adotta atti di esecuzione che stabiliscono il modello, previa consultazione delle parti interessate. Tali atti di esecuzione sono adottati secondo la procedura consultiva di cui all'articolo 63, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione di un PO II effettua almeno una valutazione entro il 31 dicembre 2022. La valutazione esamina l'efficacia, l'efficienza e l'impatto delle operazioni sostenute. E' garantito un opportuno follow-up.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Valutazione ex post", "anchor": "art_18", "frags": [[null, "<p class=\"norm\">La Commissione effettua, di propria iniziativa e in stretta cooperazione con gli Stati membri, una valutazione ex post, con l'assistenza di esperti esterni, al fine di valutare l'efficacia e l'efficienza del Fondo e la sostenibilità dei risultati ottenuti, nonché di misurare il valore aggiunto del Fondo. Tale valutazione ex post è ultimata entro il 31 dicembre 2024.</p>"]]}, "19": {"label": "Articolo 19", "heading": "Informazione e comunicazione", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri provvedono a fornire informazioni e a promuovere le azioni finanziate dal Fondo. Tali informazioni sono destinate in particolare alle persone indigenti nonché al pubblico in generale e ai media. Esse valorizzano il ruolo dell'Unione e assicurano la visibilità del contributo del Fondo, degli Stati membri e delle organizzazioni partner in relazione agli obiettivi di coesione sociale dell'Unione, senza stigmatizzare i destinatari finali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di garantire la trasparenza del sostegno fornito dal Fondo, l'autorità di gestione mantiene un elenco delle operazioni finanziate dal Fondo nella forma di un foglio elettronico che consente di selezionare, cercare, estrarre, comparare i dati e di pubblicarli agevolmente su internet. Tale elenco di operazioni comprende come minimo le seguenti informazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il nome e l'indirizzo del beneficiario,</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'importo del finanziamento dell'Unione concesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i PO I, il tipo di deprivazione materiale considerato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">L'autorità di gestione aggiorna l'elenco delle operazioni almeno ogni dodici mesi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Durante l'attuazione di un'operazione, i beneficiari e le organizzazioni partner informano il pubblico sul sostegno ottenuto dal Fondo collocando almeno un poster con informazioni sull'operazione (formato minimo A3), indicante il sostegno finanziario ricevuto dall'Unione, oppure un logo dell'Unione di dimensioni ragionevoli in un luogo facilmente visibile al pubblico. Tale requisito è osservato, senza stigmatizzare i destinatari finali, in tutti i luoghi di realizzazione di un PO I e/o di un PO II, a meno che ciò non sia possibile a causa delle condizioni della distribuzione.</div>\n</div>"], [null, "<p class=\"norm\">I beneficiari e le organizzazioni partner che dispongono di un sito web forniscono inoltre una breve descrizione dell'operazione sul proprio sito web, compresi le finalità e i risultati, evidenziando il sostegno finanziario ricevuto dall'Unione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In tutte le misure di informazione e di comunicazione adottate dal beneficiario e dalle organizzazioni partner è riconosciuto il sostegno all'operazione ricevuto dal Fondo mediante l'apposizione del logo dell'Unione e un riferimento all'Unione e al Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione informa i beneficiari della pubblicazione dell'elenco delle operazioni in conformità del paragrafo 2. L'autorità di gestione fornisce strumenti di informazione e comunicazione, compresi modelli in formato elettronico, per aiutare i beneficiari e le organizzazioni partner a rispettare gli obblighi di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel caso di un PO II:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro o l'autorità di gestione è responsabile dell'organizzazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di un'attività informativa principale che pubblicizzi l'avvio del programma operativo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di almeno un'attività informativa principale all'anno che promuova le opportunità di finanziamento e le strategie perseguite e/o presenti i risultati del programma operativo, compresi, se del caso, esempi di operazioni;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">durante l'attuazione di un'operazione, i beneficiari informano il pubblico in merito al sostegno ottenuto dal Fondo assicurando che i partecipanti all'operazione siano a conoscenza del sostegno fornito dal Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi documento, compresi attestati di partecipazione o di altro tipo, riguardante tali operazioni contiene una dichiarazione da cui risulti che il programma operativo è stato finanziato dal Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'autorità di gestione garantisce che i potenziali beneficiari abbiano accesso alle informazioni pertinenti per quanto concerne le opportunità di finanziamento, gli inviti a presentare domande e le relative condizioni nonché i criteri di selezione delle operazioni da sostenere.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Per il trattamento dei dati personali a norma degli articoli da 15 a 19 del presente regolamento, l'autorità di gestione così come i beneficiari e le organizzazioni partner si conformano alla direttiva 95/46/CE.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Cofinanziamento", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il tasso di cofinanziamento a livello del programma operativo ammonta fino all'85 % della spesa pubblica ammissibile. Può essere aumentato nelle circostanze di cui all'articolo 21, paragrafo 1. Gli Stati membri sono liberi di sostenere le iniziative del Fondo mediante risorse nazionali aggiuntive.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, su richiesta di uno Stato membro, può essere applicato un tasso di cofinanziamento del 100 % alla spesa pubblica dichiarata nelle domande di pagamento durante l’esercizio contabile che inizia il 1<span class=\"superscript\">o</span> luglio 2020 e si conclude il 30 giugno 2021.</div>\n</div>"], [null, "<p class=\"norm\">Le richieste di modifica del tasso di cofinanziamento sono presentate in conformità della procedura di modifica dei programmi operativi di cui all’articolo 9 e sono corredate del programma riveduto. Il tasso di cofinanziamento del 100 % si applica solo se la corrispondente modifica del programma è approvata dalla Commissione prima della presentazione della domanda finale di un pagamento intermedio in conformità dell’articolo 45, paragrafo 2.</p>"], [null, "<p class=\"norm\">Prima di presentare la prima domanda di pagamento per l’esercizio contabile che ha inizio il 1<span class=\"superscript\">o</span> luglio 2021, gli Stati membri notificano la tabella di cui alla sezione 5.1 dei modelli di programma operativo stabiliti all’allegato I, in cui confermano il tasso di cofinanziamento applicabile durante l’esercizio contabile che si conclude il 30 giugno 2020.</p>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">ter</span>.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, può essere applicato un tasso di cofinanziamento del 100 % alla spesa dichiarata nelle domande di pagamento per l’esercizio contabile che inizia il 1<span class=\"superscript\">o</span> luglio 2021 e si conclude il 30 giugno 2022.</div>\n</div>"], [null, "<p class=\"norm\">In deroga all’articolo 9, paragrafi 1, 2 e 3, l’applicazione del tasso di cofinanziamento del 100 % non necessita di una decisione della Commissione che approvi la modifica di un programma. Lo Stato membro notifica alla Commissione le tabelle finanziarie rivedute di cui alla sezione 5.1 dei modelli di programmi operativi stabiliti all’allegato I. Il tasso di cofinanziamento del 100 % si applica solo se le tabelle finanziarie sono notificate alla Commissione prima della presentazione della domanda finale di pagamento intermedio per l’esercizio contabile che inizia il 1<span class=\"superscript\">o</span> luglio 2021 e si conclude il 30 giugno 2022, in conformità dell’articolo 45, paragrafo 2.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La decisione della Commissione che adotta un programma operativo fissa il tasso di cofinanziamento applicabile a tale programma e l'importo massimo del sostegno del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le misure di assistenza tecnica attuate su iniziativa o per conto della Commissione possono essere finanziate a un tasso del 100 %.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Aumento dei pagamenti a favore degli Stati membri con temporanee difficoltà di bilancio", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Su richiesta di uno Stato membro i pagamenti intermedi e i pagamenti del saldo finale possono essere aumentati di 10 punti percentuali rispetto al tasso di cofinanziamento applicabile al programma operativo. Il tasso maggiorato, che non può superare il 100 %, si applica alle richieste di pagamento relative al periodo contabile in cui lo Stato membro ha presentato la richiesta e ai periodi contabili successivi in cui lo Stato membro soddisfa una delle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la valuta adottata dallo Stato membro interessato è l'euro, riceve un'assistenza macrofinanziaria dall'Unione a norma del regolamento (UE) n. 407/2010 del Consiglio (\n<span class=\"superscript\">4</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la valuta adottata dallo Stato membro interessato non è l'euro, riceve un sostegno finanziario a medio termine a norma del regolamento (CE) n. 332/2002 del Consiglio (\n<span class=\"superscript\">5</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'assistenza finanziaria è resa disponibile in conformità al trattato che istituisce il meccanismo europeo di stabilità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, il sostegno dell'Unione mediante i pagamenti intermedi e i pagamenti del saldo finale non supera il sostegno pubblico e l'importo massimo del contributo del Fondo stabiliti nella decisione della Commissione che approva il programma operativo.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Periodo di ammissibilità", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente articolo lascia impregiudicate le norme sull'ammissibilità dell'assistenza tecnica su iniziativa della Commissione di cui all'articolo 27.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le spese sono ammissibili a un sostegno del programma operativo se sono sostenute da un beneficiario e pagate tra il 1<span class=\"superscript\">o</span> dicembre 2013 e il 31 dicembre 2023.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M6\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Nel caso di spese rimborsate a norma dell'articolo 26, paragrafo 2, lettere da b) a e), le corrispondenti azioni oggetto di rimborso sono eseguite entro la trasmissione della domanda finale di pagamento intermedio per il periodo contabile finale conformemente all'articolo 45, paragrafo 6.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Non sono selezionate per il sostegno da parte del programma operativo le operazioni portate materialmente a termine o completamente attuate prima che il beneficiario abbia presentato all'autorità di gestione la domanda di finanziamento nell'ambito del programma operativo, a prescindere dal fatto che abbia effettuato tutti i relativi pagamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In caso di modifica di un programma operativo, le spese che diventano ammissibili a seguito della modifica apportata al programma operativo lo diventano solo a partire dalla data di presentazione della richiesta di modifica alla Commissione da parte dello Stato membro.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">In deroga al primo comma, le spese per le operazioni volte a promuovere la capacità di risposta per affrontare l’epidemia di COVID-19 sono ammissibili a decorrere dal 1<span class=\"superscript\">o</span> febbraio 2020.</p>"], [null, "<p class=\"modref\">\n▼M4\n</p>"], [null, "<p class=\"norm\">In deroga al primo comma, le spese per le operazioni volte a far fronte alle sfide migratorie in seguito all’aggressione militare da parte della Federazione russa sono ammissibili a decorrere dal 24 febbraio 2022.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Ammissibilità delle operazioni", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le operazioni sostenute da un programma operativo sono situate nello Stato membro indicato in detto programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le operazioni possono ricevere un sostegno da un programma operativo purché siano state selezionate secondo una procedura equa e trasparente e, sulla base dei criteri definiti in detto programma operativo o dei criteri approvati dal comitato di sorveglianza, a seconda dei casi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Non appena adottati, i criteri di selezione e gli elenchi delle operazioni selezionate per il sostegno a titolo di un PO II sono comunicati ai comitati di sorveglianza dei programmi operativi cofinanziati dal FSE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I prodotti alimentari e/o l'assistenza materiale di base per le persone indigenti possono essere acquistati direttamente dalle organizzazioni partner.</div>\n</div>"], [null, "<p class=\"norm\">I prodotti alimentari e/o l'assistenza materiale di base per le persone indigenti possono inoltre essere acquistati da un organismo pubblico e messi a disposizione delle organizzazioni partner a titolo gratuito. In tal caso i prodotti alimentari possono derivare dall'utilizzo, dal trattamento e dalla vendita di prodotti resi disponibili a norma dell'articolo 16, paragrafo 2, del regolamento (UE) n. 1308/2013, purché tale opzione sia la più economicamente vantaggiosa e non ritardi indebitamente la consegna dei prodotti alimentari alle organizzazioni partner. Gli importi derivanti da una transazione riguardante tali scorte sono utilizzati a favore delle persone indigenti e non applicati in modo da attenuare l'obbligo degli Stati membri di cui all'articolo 20 del presente regolamento di cofinanziare il programma.</p>"], [null, "<p class=\"norm\">La Commissione applica le procedure adottate a norma dell'articolo 20, lettera i), del regolamento (UE) n. 1308/2013, conformemente alle quali i prodotti delle scorte di intervento possono essere utilizzati, trattati o venduti ai fini del presente regolamento per garantirne la massima efficacia.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">I prodotti alimentari e/o l’assistenza materiale di base possono essere forniti alle persone indigenti direttamente o indirettamente, ad esempio attraverso buoni o carte, in forma elettronica o altra forma, a condizione che tali buoni, carte o altri strumenti possano essere scambiati unicamente con prodotti alimentari e/o assistenza materiale di base.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Tali prodotti alimentari e/o assistenza materiale di base sono distribuiti gratuitamente alle persone indigenti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Un’operazione può ricevere sostegno da uno o più programmi operativi cofinanziati dal Fondo e da altri strumenti dell’Unione, purché la spesa dichiarata in una domanda di pagamento per il Fondo non sia dichiarata sostegno di un altro strumento dell’Unione, o dello stesso fondo nell’ambito di un altro programma. L’importo della spesa da indicare in una domanda di pagamento del Fondo può essere calcolato per il programma o i programmi interessati su base proporzionale conformemente al documento che specifica le condizioni per il sostegno.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "24": {"label": "Articolo 24", "heading": "Forme di sostegno", "anchor": "art_24", "frags": [[null, "<p class=\"norm\">1. Il Fondo è impiegato dagli Stati membri per fornire un sostegno in forma di sovvenzioni, commesse o mediante una combinazione degli stessi. Tuttavia. tale sostegno non può assumere la forma degli aiuti di cui all'articolo 107, paragrafo 1, TFUE.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Forme di sovvenzioni", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le sovvenzioni possono assumere le seguenti forme:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimborso dei costi ammissibili effettivamente sostenuti e pagati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimborso sulla base di costi unitari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">somme forfettarie non superiori a 100 000  EUR di sostegno pubblico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti a tasso forfettario, calcolati applicando una determinata percentuale a una o più categorie di costo definite.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le opzioni di cui al paragrafo 1 possono essere combinate rispetto ad un'unica operazione se ciascuna opzione si applica a diverse categorie di costi o se sono utilizzate per fasi successive di tale operazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli importi di cui al paragrafo 1, lettere b), c) e d), sono stabiliti sulla base di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un metodo di calcolo giusto, equo e verificabile, basato su uno dei seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati statistici o altre informazioni oggettive;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati storici verificati dei singoli beneficiari o applicazione delle loro normali prassi di contabilità dei costi;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">metodi e corrispondenti costi unitari, somme forfettarie e tassi forfettari applicati nell'ambito di programmi di sovvenzione finanziati interamente dallo Stato membro interessato per una tipologia analoga di operazione e beneficiario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tassi stabiliti dal presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">caso per caso, con riferimento a una bozza di bilancio approvata a priori dall'autorità di gestione, se il sostegno pubblico non supera 100 000  EUR;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">norme di applicazione delle corrispondenti tabelle di costi unitari, somme forfettarie e tassi forfettari applicabili conformemente alle politiche dell’Unione per tipologie analoghe di operazioni e beneficiari.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli importi calcolati nelle forme di sovvenzione di cui al paragrafo 1, lettere b), c) e d), sono considerati spese ammissibili sostenute e pagate dal beneficiario ai fini dell'applicazione del titolo VI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il documento che specifica le condizioni per il sostegno a ciascuna operazione indica il metodo da applicare per stabilire i costi dell'operazione e le condizioni per il pagamento della sovvenzione.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Ammissibilità delle spese", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'ammissibilità delle spese è determinata in base a norme nazionali, fatte salve norme specifiche previste nel presente regolamento o sulla base dello stesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo -1, le spese ammissibili a un sostegno di un PO I sono:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese per l’acquisto di prodotti alimentari e/o assistenza materiale di base e le spese per l’acquisto di materiali e dispositivi di protezione individuale per le organizzazioni partner;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se un organismo pubblico acquista prodotti alimentari o assistenza materiale di base e li fornisce alle organizzazioni partner, le spese di trasporto di tali prodotti alimentari o dell'assistenza materiale di base ai depositi delle organizzazioni partner e le spese di magazzinaggio, a una percentuale forfettaria dell'1 % delle spese di cui alla lettera a) o, in casi debitamente giustificati, le spese effettivamente sostenute e pagate;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese amministrative, di preparazione, di trasporto e di magazzinaggio sostenute dalle organizzazioni partner, a una percentuale forfettaria del 5 % delle spese di cui alla lettera a), oppure del 5 % del valore dei prodotti alimentari resi disponibili a norma dell’articolo 16 del regolamento (UE) n. 1308/2013;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese sostenute dalle organizzazioni partner per la raccolta, il trasporto, il magazzinaggio e la distribuzione delle donazioni di prodotti alimentari, nonché per le attività di sensibilizzazione direttamente correlate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese per le misure di accompagnamento poste in essere e dichiarate dalle organizzazioni partner che forniscono, direttamente o nell’ambito di accordi di cooperazione, prodotti alimentari e/o assistenza materiale di base alle persone indigenti, a una percentuale forfettaria del 5 % delle spese di cui alla lettera a) del presente comma o del 5 % del valore dei prodotti alimentari smaltiti in conformità dell’articolo 16 del regolamento (UE) n. 1308/2013.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, le spese ammissibili al sostegno di un programma operativo sono le spese sostenute a norma dell'articolo 27, paragrafo 4, o, per le spese indirette sostenute in conformità dell'articolo 27, paragrafo 4, una percentuale forfettaria del 15 % dei costi diretti ammissibili per il personale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, una riduzione delle spese ammissibili di cui al paragrafo 2, lettera a), dovuta all’inosservanza del diritto applicabile da parte dell’organismo responsabile dell’acquisto di prodotti alimentari e/o assistenza materiale di base non determina una riduzione delle spese ammissibili degli altri organismi di cui al paragrafo 2, lettere c) ed e).</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Non sono ammesse al sostegno del programma operativo le seguenti spese:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">interessi passivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornitura di infrastrutture;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese per beni di seconda mano;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">imposta sul valore aggiunto salvo nei casi in cui non sia recuperabile a norma della legislazione nazionale sull'IVA.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "26a": {"label": "Articolo 26 bis", "heading": "Ammissibilità delle spese per le operazioni sostenute nel quadro di un PO I durante la loro sospensione in conseguenza dell’epidemia di COVID-19", "anchor": "art_26a", "frags": [[null, "<p class=\"norm\">I ritardi nella distribuzione di prodotti alimentari e/o assistenza materiale di base in conseguenza dell’epidemia di COVID-19 non comportano una riduzione dei costi ammissibili sostenuti dall’organismo acquirente o dalle organizzazioni partner in conformità dell’articolo 26, paragrafo 2. Tali costi possono essere dichiarati alla Commissione integralmente in conformità dell’articolo 26, paragrafo 2, prima della distribuzione dei prodotti alimentari e/o assistenza materiale di base alle persone indigenti, a condizione che la distribuzione sia ripresa una volta superata la crisi connessa con l’epidemia di COVID-19.</p>"], [null, "<p class=\"norm\">In caso di deterioramento dei prodotti alimentari dovuto alla sospensione della distribuzione in conseguenza dell’epidemia di COVID-19, le spese di cui all’articolo 26, paragrafo 2, lettera a), non sono ridotte.</p>"]]}, "26b": {"label": "Articolo 26 ter", "heading": "Ammissibilità delle spese per le operazioni sostenute nel quadro di un PO II o dell’assistenza tecnica durante la loro sospensione in conseguenza dell’epidemia di COVID-19", "anchor": "art_26b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora l’attuazione delle operazioni sia sospesa in conseguenza dell’epidemia di COVID-19, uno Stato membro può considerare ammissibili le spese sostenute durante la sospensione anche se non sono prestati servizi, purché siano soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione dell’operazione è sospesa dopo il 31 gennaio 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sospensione dell’operazione è dovuta all’epidemia di COVID-19;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese sono state sostenute e pagate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese costituiscono un costo reale per il beneficiario e non possono essere recuperate né compensate; per i recuperi e le compensazioni che non sono a carico dello Stato membro, quest’ultimo può considerare che il rispetto di tale condizione sia attestato sulla base di una dichiarazione del beneficiario; i recuperi e le compensazioni sono detratti dalle spese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese sono limitate al periodo di sospensione dell’operazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le operazioni in cui il beneficiario è rimborsato sulla base di opzioni semplificate in materia di costi e l’attuazione delle azioni che costituiscono la base del rimborso è sospesa in conseguenza dell’epidemia di COVID-19, lo Stato membro interessato può rimborsare il beneficiario sulla base delle realizzazioni previste per il periodo di sospensione, anche qualora non sia realizzata alcuna azione, purché siano soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione delle azioni è sospesa dopo il 31 gennaio 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sospensione delle azioni è dovuta all’epidemia di COVID-19;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le opzioni semplificate in materia di costi corrispondono a un costo reale sostenuto dal beneficiario, che deve essere dimostrato dal beneficiario e che non può essere recuperato né compensato; per i recuperi e le compensazioni che non sono a carico dello Stato membro, quest’ultimo può considerare che il rispetto di tale condizione sia attestato sulla base di una dichiarazione del beneficiario; i recuperi e le compensazioni sono detratti dall’importo corrispondente all’opzione semplificata in materia di costi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il rimborso al beneficiario è limitato al periodo di sospensione delle azioni.</p>\n<p class=\"list\">Per le operazioni di cui al primo comma del presente paragrafo, lo Stato membro può anche rimborsare il beneficiario sulla base dei costi di cui all’articolo 25, paragrafo 1, lettera a), purché siano soddisfatte le condizioni di cui al paragrafo 1 del presente articolo.</p>\n<p class=\"list\">Qualora uno Stato membro rimborsi il beneficiario sulla base del primo e del secondo comma, esso provvede affinché una medesima spesa sia rimborsata una sola volta.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "26c": {"label": "Articolo 26 quarter", "heading": "Ammissibilità delle spese per le operazioni sostenute nel quadro di un PO II o dell’assistenza tecnica e non pienamente attuate in conseguenza dell’epidemia di COVID-19", "anchor": "art_26c", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Uno Stato membro può considerare ammissibili le spese per operazioni non pienamente attuate in conseguenza dell’epidemia di COVID-19, purché siano soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione dell’operazione termina dopo il 31 gennaio 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il etrmine dell’attuazione dell’operazione è dovuto all’epidemia di COVID-19;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese sostenute prima del termine dell’annullamento dell’operazione erano state sostenute e pagate dal beneficiario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le operazioni in cui il beneficiario è rimborsato sulla base di opzioni semplificate in materia di costi, uno Stato membro può considerare ammissibili le spese per operazioni non pienamente attuate in consegueza dell’epidemia di COVID-19, purché siano soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione dell’operazione termina dopo il 31 gennaio 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il termine dell’attuazione dell’operazione è dovuto all’epidemia di COVID-19;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni contemplate dalle opzioni semplificate in materia di costi erano state attuate almeno in parte prima del termine dell’attuazione dell’operazione.</p>\n<p class=\"list\">Per le operazioni di cui al primo comma del presente paragrafo, lo Stato membro può anche rimborsare il beneficiario sulla base dei costi di cui all’articolo 25, paragrafo 1, lettera a), purché siano soddisfatte le condizioni di cui al paragrafo 1 del presente articolo.</p>\n<p class=\"list\">Qualora uno Stato membro rimborsi il beneficiario sulla base di entrambi il primo e il secondo comma, esso provvede affinché la medesima spesa sia rimborsata una sola volta.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Assistenza tecnica", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa o per conto della Commissione ed entro una soglia dello 0,35 % della sua dotazione annuale, il Fondo può finanziare le attività di preparazione, sorveglianza, assistenza tecnica e amministrativa, audit, informazione, controllo e valutazione necessarie all'attuazione del presente regolamento, nonché le attività di cui all'articolo 10.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione consulta gli Stati membri e le organizzazioni che rappresentano le organizzazioni partner a livello di Unione in merito all'utilizzo previsto dell'assistenza tecnica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione fissa ogni anno, mediante atti di esecuzione, i suoi piani sul tipo di azioni relative alle misure di cui al paragrafo 1, quando è previsto un contributo del Fondo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Su iniziativa degli Stati membri ed entro una soglia del 5 % della dotazione del Fondo al momento dell’adozione del programma operativo e del 5 % delle risorse aggiuntive di cui all’articolo 6 <span class=\"italics\">bis</span>, paragrafo 1, il programma operativo può finanziare le attività di preparazione, gestione, sorveglianza, assistenza tecnica e amministrativa, audit, informazione, controllo e valutazione necessarie all’attuazione del Fondo, compresi i costi per la preparazione e il funzionamento di sistemi di buoni, ove tali costi siano sostenuti dall’autorità di gestione o da un altro organismo pubblico che non sia un’organizzazione partner. Il programma operativo può inoltre finanziare l’assistenza tecnica e lo sviluppo delle capacità delle organizzazioni partner e di qualsiasi altro attore coinvolto nell’attuazione del Fondo, anche per promuovere la capacità di risposta alle crisi per far fronte all’epidemia di COVID-19. Le azioni di cui al presente paragrafo possono riguardare il periodo di programmazione successivo, anche per garantire il proseguimento del sostegno del Fondo attraverso altri fondi dell’Unione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "28": {"label": "Articolo 28", "heading": "Principi generali dei sistemi di gestione e controllo", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">I sistemi di gestione e controllo prevedono, a norma dell'articolo 5, paragrafo 7:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione delle funzioni di ciascun organismo coinvolto nella gestione e nel controllo e la ripartizione delle funzioni all'interno di ciascun organismo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'osservanza del principio della separazione delle funzioni fra tali organismi e all'interno degli stessi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure atte a garantire la correttezza e la regolarità delle spese dichiarate;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sistemi informatizzati per la contabilità, per la memorizzazione e la trasmissione dei dati finanziari e dei dati sugli indicatori, per la sorveglianza e le relazioni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sistemi di predisposizione delle relazioni e sorveglianza nei casi in cui l'organismo responsabile affida l'esecuzione dei compiti a un altro organismo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">disposizioni per l'audit del funzionamento dei sistemi di gestione e controllo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sistemi e procedure per garantire una pista di controllo adeguata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la prevenzione, il rilevamento e la correzione di irregolarità, comprese le frodi, e il recupero di importi indebitamente versati, compresi, se del caso, gli interessi su ritardati pagamenti.</p>\n</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Responsabilità in caso di gestione concorrente", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">Conformemente al principio di gestione concorrente, gli Stati membri e la Commissione sono responsabili della gestione e del controllo dei programmi secondo le rispettive responsabilità stabilite dal presente regolamento.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Responsabilità degli Stati membri", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adempiono agli obblighi di gestione, controllo e audit e assumono le responsabilità che ne derivano indicate nelle norme sulla gestione concorrente di cui al regolamento finanziario e al presente regolamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Sulla base di un’analisi dei rischi potenziali, gli Stati membri possono stabilire prescrizioni meno rigorose in materia di pista di controllo e audit per quanto riguarda la distribuzione di prodotti alimentari e/o assistenza materiale alle persone indigenti durante il periodo dell’epidemia di COVID-19.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri prevengono, individuano e correggono le irregolarità e recuperano gli importi indebitamente versati compresi, se del caso, gli interessi di mora. Essi notificano alla Commissione le irregolarità che superano i 10 000  EUR di contributo del Fondo e la informano sui progressi significativi dei relativi procedimenti amministrativi e giudiziari.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Gli Stati membri non notificano alla Commissione le irregolarità in relazione a quanto segue:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">casi in cui l'irregolarità consiste unicamente nella mancata esecuzione, in tutto o in parte, di un'operazione rientrante nel programma operativo cofinanziato in seguito al fallimento del beneficiario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">casi segnalati spontaneamente dal beneficiario all'autorità di gestione o all'autorità di certificazione prima del rilevamento da parte di una della due autorità, sia prima che dopo il versamento del contributo pubblico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">casi rilevati e corretti dall'autorità di gestione o dall'autorità di certificazione prima dell'inclusione delle spese in questione in una dichiarazione di spesa presentata alla Commissione.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">In tutti gli altri casi, in particolare in caso di irregolarità precedenti un fallimento o nei casi di sospetta frode, le irregolarità rilevate e le relative misure preventive e correttive sono notificate alla Commissione.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">Quando un importo indebitamente versato a un beneficiario per un’operazione non può essere recuperato per colpa o negligenza di uno Stato membro, spetta a quest’ultimo rimborsare l’importo in questione al bilancio dell’Unione. Gli Stati membri possono decidere di non recuperare un importo versato indebitamente se l’importo che deve essere recuperato dal beneficiario non supera, al netto degli interessi, 250 EUR di contributo del Fondo a un’operazione in un esercizio contabile.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo alle norme dettagliate supplementari relative ai criteri per la definizione dei casi di irregolarità da segnalare, ai dati da fornire e alle condizioni e procedure da applicare onde determinare se gli importi non recuperabili debbano essere rimborsati dagli Stati membri.</p>"], [null, "<p class=\"norm\">La Commissione adotta atti di esecuzione secondo la procedura consultiva di cui all'articolo 63, paragrafo 2, per fissare la frequenza della comunicazione e il formato da utilizzare.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri garantiscono l'introduzione di efficaci modalità di esame dei reclami concernenti il Fondo. La definizione della portata, delle norme e delle procedure relative a tali modalità compete agli Stati membri conformemente ai relativi quadri istituzionali e giuridici. Gli Stati membri, su richiesta della Commissione, esaminano i reclami presentati alla Commissione che ricadono nell'ambito delle suddette modalità. Su richiesta, gli Stati membri informano la Commissione dei risultati di tali esami.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Tutti gli scambi ufficiali di informazioni tra gli Stati membri e la Commissione avvengono utilizzando un sistema di scambio elettronico di dati. La Commissione adotta atti di esecuzione al fine di stabilire modalità e condizioni alle quali detto sistema di scambio elettronico di dati debba conformarsi. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 63, paragrafo 3.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Designazione delle autorità", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per ciascun programma operativo ogni Stato membro designa un'autorità o un organismo pubblico nazionale quale autorità di gestione. La stessa autorità di gestione può essere designata per due programmi operativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per ciascun programma operativo lo Stato membro designa un'autorità o un organismo pubblico nazionale quale autorità di certificazione, fato salvo il paragrafo 3. La stessa autorità di certificazione può essere designata per due programmi operativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può designare per un programma operativo un'autorità di gestione affinché svolga anche le funzioni di autorità di certificazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per ciascun programma operativo lo Stato membro designa un'autorità o un organismo pubblico nazionale quale autorità di audit, funzionalmente indipendente dall'autorità di gestione e dall'autorità di certificazione. La stessa autorità di audit può essere designata per due programmi operativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Purché sia rispettato il principio della separazione delle funzioni, l'autorità di gestione, l'autorità di certificazione per il PO I e il PO II per i quali l'importo complessivo del sostegno del Fondo non supera 250 000 000  EUR, l'autorità di audit, possono fare parte della stessa autorità o organismo pubblico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Lo Stato membro può designare uno o più organismi intermedi per lo svolgimento di determinati compiti dell'autorità di gestione o dell'autorità di certificazione sotto la responsabilità di detta autorità. I relativi accordi tra l'autorità di gestione o di certificazione e gli organismi intermedi sono registrati formalmente per iscritto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l'autorità di gestione può affidare la gestione di parte di un programma operativo ad un organismo intermedio mediante un accordo scritto tra l'organismo intermedio e lo Stato membro o l'autorità di gestione. L'organismo intermedio garantisce la propria solvibilità e competenza nel settore interessato, nonché la propria capacità di gestione amministrativa e finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Lo Stato membro definisce per iscritto le norme che disciplinano le sue relazioni con le autorità di gestione, le autorità di certificazione e le autorità di audit, le relazioni tra dette autorità e le relazioni tra queste ultime e la Commissione.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Funzioni dell'autorità di gestione", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione è responsabile della gestione del programma operativo conformemente al principio della sana gestione finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto riguarda la gestione del programma operativo, l'autorità di gestione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assiste, se del caso, il comitato di sorveglianza di cui all'articolo 11 e fornisce a esso le informazioni necessarie allo svolgimento dei suoi compiti, in particolare i dati relativi ai progressi del programma operativo nel raggiungimento degli obiettivi, i dati finanziari e i dati relativi a indicatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elabora e presenta alla Commissione, previa consultazione delle parti interessate, evitando nel contempo conflitti di interessi per il PO I, o previa approvazione del comitato di sorveglianza di cui all'articolo 11 relativamente al PO II, relazioni di attuazione annuali e finali di cui all'articolo 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rende disponibili agli organismi intermedi e ai beneficiari informazioni pertinenti rispettivamente per l'esecuzione dei loro compiti e l'attuazione delle operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituisce un sistema di registrazione e conservazione informatizzata dei dati relativi a ciascuna operazione, necessari per la sorveglianza, la valutazione, la gestione finanziaria, la verifica e l'audit, compresi i dati su singoli partecipanti alle operazioni cofinanziate dal PO II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che i dati di cui alla lettera d) siano raccolti, inseriti e memorizzati nel sistema di cui alla lettera d) a norma della direttiva 95/46/CE e, ove possibile, suddivisi per sesso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto concerne la selezione delle operazioni, l'autorità di gestione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elabora e, se necessario e previa approvazione, applica procedure e/o criteri di selezione adeguati, non discriminatori e trasparenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che l'operazione selezionata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rientri nel campo di intervento del Fondo e del programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispetti i criteri stabili nel programma operativo e negli articoli 22, 23 e 26;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tenga conto, se del caso, dei principi stabiliti all'articolo 5, paragrafi 11, 12, 13 e 14;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché sia fornito al beneficiario un documento contenente le condizioni per il sostegno relative a ciascuna operazione, compresi i requisiti specifici concernenti i prodotti o servizi da fornire nell'ambito dell'operazione, il piano finanziario e il termine per l'esecuzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si accerta che il beneficiario abbia la capacità amministrativa, finanziaria e operativa per soddisfare le condizioni di cui alla lettera c) prima dell'approvazione dell'operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si accerta che, ove l'operazione sia iniziata prima della presentazione di una domanda di finanziamento all'autorità di gestione, sia stato osservato il diritto applicabile pertinente per l'operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilisce il tipo di assistenza materiale per il PO I e il tipo di azione per il PO II cui è attribuita la spesa relativa a una specifica operazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto concerne la gestione finanziaria e il controllo del programma operativo, l'autorità di gestione:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica che i prodotti e i servizi cofinanziati siano stati forniti e che l’operazione sia conforme al diritto applicabile, al programma operativo e alle condizioni per il sostegno dell’operazione e</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora i costi debbano essere rimborsati ai sensi dell’articolo 25, paragrafo 1, lettera a), che l’importo della spesa dichiarata dai beneficiari in relazione a tali costi sia stato pagato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora i costi debbano essere rimborsati a norma dell’articolo 25, paragrafo 1, lettere b), c) e d), che siano state rispettate le condizioni per il rimborso della spesa al beneficiario;</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce che i beneficiari coinvolti nell'attuazione di operazioni rimborsate sulla base dei costi ammissibili effettivamente sostenuti mantengano un sistema di contabilità separata o una codificazione contabile adeguata per tutte le transazioni relative a un'operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituisce misure antifrode efficaci e proporzionate, tenendo conto dei rischi individuati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilisce procedure per far sì che tutti i documenti relativi alle spese e agli audit necessari per garantire una pista di controllo adeguata siano conservati secondo quanto disposto all'articolo 28, lettera g);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elabora la dichiarazione di gestione e la sintesi annuale di cui all'articolo 59, paragrafo 5, primo comma, lettere a) e b), del regolamento finanziario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le verifiche ai sensi del paragrafo 4, lettera a), comprendono le seguenti procedure:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifiche amministrative rispetto a ciascuna domanda di rimborso presentata dai beneficiari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifiche sul posto delle operazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La frequenza e la portata delle verifiche sul posto sono proporzionali all'ammontare del sostegno pubblico a un'operazione e al livello di rischio individuato da tali verifiche e dagli audit effettuati dall'autorità di audit per il sistema di gestione e controllo nel suo complesso.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le verifiche sul posto di singole operazioni ai sensi del paragrafo 5, primo comma, lettera b), possono essere svolte a campione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora l'autorità di gestione sia anche un beneficiario nell'ambito del programma operativo, le disposizioni relative alle verifiche di cui al paragrafo 4, lettera a), garantiscono un'adeguata separazione delle funzioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo alle norme indicanti le informazioni relative ai dati da registrare e conservare in formato elettronico nell'ambito di un sistema di sorveglianza istituito a norma del paragrafo 2, lettera d), del presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione adotta atti di esecuzione che definiscono le specifiche tecniche del sistema istituito a norma del paragrafo 2, lettera d) del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 63, paragrafo 3.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo alla definizione in dettaglio dei requisiti minimi per la pista di controllo di cui al paragrafo 4, lettera d), del presente articolo, relativamente ai documenti contabili e alla documentazione di supporto da conservare al livello dell'autorità di certificazione, dell'autorità di gestione, degli organismi intermedi e dei beneficiari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta atti di esecuzione riguardo al modello per la dichiarazione di gestione di cui al paragrafo 4, lettera e). Tali atti di esecuzione sono adottati secondo la procedura consultiva di cui all'articolo 63, paragrafo 2.</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Funzioni dell'autorità di certificazione", "anchor": "art_33", "frags": [[null, "<p class=\"norm\">L'autorità di certificazione di un programma operativo è incaricata in particolare di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborare e trasmettere alla Commissione le domande di pagamento e certificare che provengono da sistemi di contabilità affidabili, sono basate su documenti giustificativi verificabili e sono state oggetto di verifiche da parte dell'autorità di gestione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare i bilanci di cui all'articolo 59, paragrafo 5, primo comma, lettera a), del regolamento finanziario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">certificare la completezza, esattezza e veridicità dei bilanci e che le spese in esse iscritte sono conformi al diritto applicabile e sono state sostenute in rapporto ad operazioni selezionate per il finanziamento conformemente ai criteri applicabili al programma operativo e nel rispetto del diritto applicabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire l'esistenza di un sistema di registrazione e conservazione informatizzata dei dati contabili per ciascuna operazione, che gestisce tutti i dati necessari per la preparazione delle domande di pagamento e dei bilanci, compresi i dati degli importi recuperabili, recuperati e ritirati a seguito della soppressione totale o parziale del contributo a favore di un'operazione o di un programma operativo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire, ai fini della preparazione e presentazione delle domande di pagamento, di aver ricevuto informazioni adeguate dall'autorità di gestione in merito alle procedure seguite e alle verifiche effettuate in relazione alle spese;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tenere conto, nel preparare e presentare le domande di pagamento, dei risultati di tutte le attività di audit svolte dall'autorità di audit o sotto la sua responsabilità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mantenere una contabilità informatizzata delle spese dichiarate alla Commissione e del corrispondente contributo pubblico versato ai beneficiari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tenere una contabilità degli importi recuperabili e degli importi ritirati a seguito della soppressione totale o parziale del contributo a un'operazione. Gli importi recuperati sono restituiti al bilancio dell'Unione prima della chiusura del programma operativo detraendoli dalla dichiarazione di spesa successiva.</p>\n</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Funzioni dell'autorità di audit", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità di audit garantisce lo svolgimento di attività di audit sul corretto funzionamento del sistema di gestione e controllo del programma operativo e su un campione adeguato di operazioni sulla base delle spese dichiarate.</div>\n</div>"], [null, "<p class=\"norm\">I controlli di audit cui sono sottoposte le spese dichiarate si basano su un campione rappresentativo o, se del caso, su una verifica di convalida e, come regola generale, su un metodo di campionamento statistico.</p>"], [null, "<p class=\"norm\">Un metodo di campionamento non statistico può essere impiegato previo giudizio professionale dell'autorità di audit in casi debitamente giustificati conformemente alle norme internazionalmente accettate in materia di audit e, in ogni caso, se il numero di operazioni in un periodo contabile è insufficiente a consentire il ricorso a un metodo statistico.</p>"], [null, "<p class=\"norm\">In tali casi, la dimensione del campione è sufficiente a consentire all'autorità di audit di redigere un parere di audit valido, a norma dell'articolo 59, paragrafo 5, primo comma, lettera b), del regolamento finanziario.</p>"], [null, "<p class=\"norm\">Il metodo di campionamento non statistico copre almeno il 5 % delle operazioni per le quali sono state dichiarate spese alla Commissione durante un periodo contabile e il 10 % delle spese dichiarate alla Commissione durante un periodo contabile.</p>"], [null, "<p class=\"norm\">Qualora l'importo complessivo del sostegno fornito dal Fondo a un PO I non superi 35 000 000  EUR, l'autorità di audit è autorizzata a limitare le attività di controllo ad un audit annuale del sistema che preveda anche una verifica di convalida su una combinazione di test delle operazioni casuali e basati sul rischio. L'attività di audit è svolta in conformità alle norme in materia di controllo riconosciute a livello internazionale e quantifica ogni anno il livello di errori presenti nelle dichiarazioni di spesa certificate alla Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora le attività di audit siano svolte da un organismo diverso dall'autorità di audit, quest'ultima si accerta che tale organismo disponga della necessaria indipendenza funzionale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L'autorità di audit si assicura che le attività di audit tengano conto degli standard riconosciuti a livello internazionale in materia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Entro otto mesi dall'adozione di un programma operativo, l'autorità di audit prepara una strategia di audit per lo svolgimento dell'attività di audit. Detta strategia definisce la metodologia di audit, il metodo di campionamento o, se del caso, il metodo della verifica di convalida per le attività di audit sulle operazioni e la pianificazione delle attività di audit in relazione al periodo contabile corrente e ai due successivi. La strategia di audit è aggiornata annualmente a decorrere dal 2016 e fino al 2024 compreso. Nel caso in cui si applichi un sistema comune di gestione e controllo a due programmi operativi, è possibile preparare un'unica strategia di audit per i programmi operativi interessati. L'autorità di audit presenta alla Commissione la strategia di audit su richiesta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'autorità di audit prepara:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un parere di audit a norma dell'articolo 59, paragrafo 5, primo comma, lettera b), del regolamento finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una relazione di controllo che evidenzi le principali risultanze delle attività di audit svolte a norma del paragrafo 1, comprese le carenze riscontrate nei sistemi di gestione e di controllo e le azioni correttive proposte e attuate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nel caso in cui si applichi un sistema comune di gestione e controllo a due programmi operativi, le informazioni di cui al primo comma, lettera b), possono essere raggruppate in una relazione unica.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta atti di esecuzione per stabilire i modelli per la strategia di audit, il parere di audit e la relazione di controllo. Tali atti di esecuzione sono adottati secondo la procedura consultiva di cui all'articolo 63, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo all'ambito e ai contenuti degli audit relativi alle operazioni e ai conti, nonché la metodologia per la selezione del campione di operazioni di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo alle norme dettagliate sull'uso dei dati raccolti durante gli audit effettuati da funzionari della Commissione o da rappresentanti autorizzati della Commissione.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Procedura per la designazione dell'autorità di gestione e dell'autorità di certificazione", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro notifica alla Commissione la data e la forma delle designazioni, che sono eseguite al livello appropriato, dell'autorità di gestione e, se del caso, dell'autorità di certificazione, prima della presentazione della prima richiesta di pagamento intermedio alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le designazioni di cui al paragrafo 1 si basa su una relazione e un parere di un organismo di audit indipendente che valuta la conformità, da parte delle autorità, ai criteri relativi all'ambiente di controllo interno, alla gestione del rischio, alle attività di controllo e di gestione e alla sorveglianza stabiliti all'allegato IV.</div>\n</div>"], [null, "<p class=\"norm\">L'organismo di audit indipendente è l'autorità di audit ovvero un altro organismo di diritto pubblico o privato con la necessaria capacità di audit, indipendente dall'autorità di gestione e, se del caso, dall'autorità di certificazione, e che svolge il proprio lavoro tenendo conto degli standard in materia di audit accettati a livello internazionale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono decidere che un'autorità di gestione o un'autorità di certificazione designata per un programma operativo cofinanziato dal FSE a norma del regolamento (UE) n. 1303/2013 sia considerata designata ai fini del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione può chiedere, entro un mese dalla notifica delle designazioni di cui al paragrafo 1, la relazione e il parere dell'organismo di audit indipendente di cui al paragrafo 2 e la descrizione delle funzioni e delle procedure in essere per l'autorità di gestione o, se del caso, l'autorità di certificazione. La Commissione decide se richiedere tali documenti sulla base di una valutazione dei rischi.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione può formulare osservazioni entro due mesi dal ricevimento dei documenti di cui al primo comma.</p>"], [null, "<p class=\"norm\">Fatto salvo l'articolo 46, l'esame di tali documenti non interrompe il trattamento delle domande per i pagamenti intermedi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora i risultati degli audit e dei controlli esistenti mostrino che l'autorità designata non ottempera più ai criteri di cui al paragrafo 2, lo Stato membro stabilisce, a un livello appropriato e tenuto conto della gravità del problema, un periodo di prova, durante il quale sono attuate le necessarie azioni correttive.</div>\n</div>"], [null, "<p class=\"norm\">Qualora l'autorità designata non attui le necessarie azioni correttive entro il periodo di prova stabilito dallo Stato membro, lo Stato membro, al livello appropriato, pone termine a tale designazione.</p>"], [null, "<p class=\"norm\">Lo Stato membro notifica senza indugio alla Commissione quando un'autorità designata è sottoposta a un periodo di prova, fornendo informazioni sul rispettivo periodo di prova, quando si è concluso il periodo di prova dopo l'attuazione delle azioni correttive, nonché quando è posto fine alla designazione di un'autorità. La notifica, da parte di uno Stato membro, che un organismo designato è stato sottoposto a un periodo di prova, fatta salva l'applicazione dell'articolo 46, non interrompe il trattamento delle domande di pagamenti intermedi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Qualora sia posto fine alla designazione di un'autorità di gestione o di certificazione, gli Stati membri designano, secondo la procedura di cui al paragrafo 2, un nuovo organismo ad assumerne le funzioni e ne informano la Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta atti di esecuzione riguardo al modello per la relazione e al parere dell'organismo di audit indipendente, nonché alla descrizione delle funzioni e delle procedure in essere per l'autorità di gestione e, se del caso, dell'autorità di certificazione. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 63, paragrafo 3.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Poteri e responsabilità della Commissione", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione si accerta, sulla base delle informazioni disponibili, comprese le informazioni in merito alla designazione degli organismi responsabili della gestione e del controllo, i documenti forniti ogni anno, conformemente all'articolo 59, paragrafo 5, del regolamento finanziario, dagli organismi designati, le relazioni di controllo, le relazioni di attuazione annuali e gli audit effettuati da organismi nazionali e dell'Unione, che gli Stati membri abbiano predisposto sistemi di gestione e di controllo conformi al presente regolamento e che tali sistemi funzionino in modo efficace durante l'attuazione dei programmi operativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I funzionari della Commissione o suoi rappresentanti autorizzati possono svolgere audit o controlli sul posto a condizione che si dia all'autorità competente nazionale un preavviso di almeno dodici giorni lavorativi, salvo in casi urgenti. La Commissione rispetta il principio di proporzionalità tenendo conto della necessità di evitare inutili duplicazioni degli audit o dei controlli svolti dagli Stati membri, del livello di rischio per il bilancio dell'Unione e della necessità di ridurre al minimo gli oneri amministrativi a carico dei beneficiari conformemente al presente regolamento. L'ambito di tali audit o controlli può comprendere, in particolare, una verifica dell'efficace funzionamento dei sistemi di gestione e controllo di un programma operativo o di parte dello stesso, nelle operazioni e la valutazione della sana gestione finanziaria delle operazioni o dei programmi. A detti controlli di audit o controlli possono partecipare funzionari o rappresentanti autorizzati degli Stati membri.</div>\n</div>"], [null, "<p class=\"norm\">Funzionari della Commissione o suoi rappresentanti autorizzati, debitamente legittimati ad effettuare audit o controlli sul posto, hanno accesso a tutti i necessari registri, documenti e metadati, a prescindere dal mezzo su cui sono conservati, relativi a operazioni finanziate dal Fondo o ai sistemi di gestione e controllo. Su richiesta, gli Stati membri forniscono alla Commissione copie di tali registri, documenti e metadati.</p>"], [null, "<p class=\"norm\">I poteri descritti nel presente paragrafo non pregiudicano l'applicazione delle disposizioni nazionali che riservano alcuni atti a funzionari specificamente designati dalla legislazione nazionale. I funzionari della Commissione e i suoi rappresentanti autorizzati non partecipano, in particolare, alle visite domiciliari o agli interrogatori formali di persone nell'ambito della legislazione nazionale. Tuttavia, tali funzionari e rappresentanti hanno accesso alle informazioni così raccolte, fatte salve le competenze dei tribunali nazionali e nel pieno rispetto dei diritti fondamentali dei soggetti giuridici interessati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione può chiedere a uno Stato membro di adottare i provvedimenti necessari per garantire l'efficace funzionamento dei suoi sistemi di gestione e controllo o per verificare la regolarità delle spese in conformità al presente regolamento.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Cooperazione con le autorità di audit", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione collabora con le autorità di audit per coordinarne i piani e metodi di audit e scambia immediatamente con tali autorità i risultati dei controlli effettuati sui sistemi di gestione e di controllo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al fine di facilitare tale cooperazione, laddove designi più di un'autorità di audit, lo Stato membro può designare un organismo di coordinamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione, le autorità di audit e l'eventuale organismo di coordinamento si riuniscono periodicamente e, in linea di massima, almeno una volta all'anno, salvo diverso accordo, per esaminare la relazione di controllo annuale, il parere di audit e la strategia di audit e per uno scambio di opinioni su questioni relative al miglioramento dei sistemi di gestione e controllo.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Impegni di bilancio", "anchor": "art_38", "frags": [[null, "<p class=\"norm\">Gli impegni di bilancio dell'Unione per ciascun programma operativo sono effettuati in rate annuali nel periodo compreso tra il 1<span class=\"superscript\">o</span> gennaio 2014 e il 31 dicembre 2020. La decisione della Commissione di adottare un programma operativo costituisce una decisione di finanziamento ai sensi dell'articolo 84 del regolamento finanziario e, una volta notificata allo Stato membro interessato, un impegno giuridico ai sensi di tale regolamento</p>"], [null, "<p class=\"norm\">Per ciascun programma operativo, l'impegno di bilancio relativo alla prima rata segue l'adozione del programma operativo da parte della Commissione.</p>"], [null, "<p class=\"norm\">Gli impegni di bilancio relativi alle rate successive sono effettuati dalla Commissione entro il 1<span class=\"superscript\">o</span> maggio di ogni anno, sulla base della decisione di cui al secondo comma, salvo nel caso in cui si applichi l'articolo 16 del regolamento finanziario.</p>"]]}, "39": {"label": "Articolo 39", "heading": "Pagamenti da parte della Commissione", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I pagamenti, da parte della Commissione, dei contributi del Fondo a ciascun programma operativo sono effettuati conformemente agli stanziamenti di bilancio e sono subordinati ai fondi disponibili. Ogni pagamento è imputato all'impegno di bilancio aperto meno recente del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I pagamenti avvengono in forma di prefinanziamento, di pagamenti intermedi e di pagamento del saldo finale.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Pagamenti intermedi e pagamento del saldo finale da parte della Commissione", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione rimborsa a titolo di pagamento intermedio il 90 % dell'importo risultante dall'applicazione del tasso di cofinanziamento, stabilito nella decisione che adotta il programma operativo, alle spese pubbliche ammissibili che figurano nella domanda di pagamento. La Commissione determina gli importi residui da rimborsare a titolo di pagamento intermedio o da recuperare a norma dell'articolo 50.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga all'articolo 21, il contributo a titolo del Fondo mediante i pagamenti intermedi e il pagamento del saldo finale non supera l'importo massimo del contributo a titolo del Fondo, secondo quanto stabilito nella decisione della Commissione che approva il programma operativo.</div>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Domande di pagamento", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La domanda di pagamento da presentare alla Commissione fornisce tutte le informazioni necessarie perché la Commissione possa presentare i conti a norma dell'articolo 68, paragrafo 3, del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le domande di pagamento per il programma operativo nel suo insieme e per l'assistenza tecnica di cui all'articolo 27, paragrafo 4, comprendono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'importo totale delle spese pubbliche ammissibili sostenute dal beneficiario e pagate nell'attuazione delle operazioni, come contabilizzato nel sistema contabile dell'autorità di certificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'importo totale della spesa pubblica relativa all'attuazione delle operazioni, come contabilizzato nel sistema contabile dell'autorità di certificazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le spese ammissibili contenute in una domanda di pagamento sono giustificate da fatture quietanzate o da documenti contabili di valore probatorio equivalente, salvo per le forme di sostegno di cui all'articolo 25, paragrafo 1, lettere b), c) e d). Per tali forme di sostegno, gli importi indicati nella domanda di pagamento sono i costi calcolati sulla base applicabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta atti di esecuzione che stabiliscono il modello per le domande di pagamento. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 63, paragrafo 3.</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Pagamenti ai beneficiari", "anchor": "art_42", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione provvede affinché, nel caso di sovvenzioni a favore delle organizzazioni partner, i beneficiari dispongano di un fondo di cassa che sia sufficiente a garantire l'attuazione delle operazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In funzione della disponibilità dei finanziamenti a titolo di prefinanziamento e dei pagamenti intermedi, l'autorità di gestione assicura che un beneficiario riceva l'importo totale della spesa pubblica ammissibile dovuta entro 90 giorni dalla data di presentazione della domanda di pagamento da parte del beneficiario. Non si applica nessuna detrazione o trattenuta né alcun onere specifico o di altro genere con effetto equivalente che porti alla riduzione degli importi dovuti ai beneficiari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il termine di pagamento di cui al paragrafo 2 può essere sospeso dall’autorità di gestione in uno dei seguenti casi debitamente motivati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo della domanda di pagamento non è dovuto o non sono stati prodotti i documenti giustificativi appropriati, tra cui la documentazione necessaria per le verifiche della gestione a norma dell’articolo 32, paragrafo 4, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stata avviata un’indagine in merito a un’eventuale irregolarità che incide sulla spesa in questione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il beneficiario interessato è informato per iscritto della sospensione e dei motivi della stessa. Il rimanente periodo utile per il pagamento riprende a decorrere dalla data di ricezione delle informazioni o dei documenti richiesti o dalla data di esecuzione dell’indagine.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "43": {"label": "Articolo 43", "heading": "Uso dell'euro", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli importi che figurano nei programmi operativi presentati dagli Stati membri, le dichiarazioni di spesa, le richieste di pagamento, i bilanci e le spese indicate nelle relazioni di attuazione annuali e finali sono espressi in euro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri che non hanno adottato l'euro come valuta nazionale alla data della domanda di pagamento, convertono in euro gli importi delle spese sostenute in valuta nazionale. Tali importi sono convertiti in euro al tasso di cambio contabile mensile della Commissione in vigore nel mese durante il quale la spesa è stata contabilizzata dall'autorità di certificazione del programma operativo interessato. Il tasso di cambio è pubblicato in formato elettronico ogni mese dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando l'euro diventa la valuta di uno Stato membro, la procedura di conversione di cui al paragrafo 2 continua ad applicarsi a tutte le spese contabilizzate dall'autorità di certificazione prima della data di entrata in vigore del tasso di conversione fisso tra la valuta nazionale e l'euro.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Pagamento e liquidazione del prefinanziamento", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A seguito della decisione che approva il programma operativo, la Commissione versa, a titolo di prefinanziamento, un importo pari all'11 % del contributo totale del Fondo al programma operativo interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il prefinanziamento è utilizzato esclusivamente per pagamenti ai beneficiari nell'attuazione del programma operativo ed è a tale scopo messo immediatamente a disposizione dell'organismo responsabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L'importo complessivo versato a titolo di prefinanziamento è rimborsato alla Commissione se per il programma operativo interessato non è inviata alcuna domanda di pagamento entro 24 mesi dalla data in cui la Commissione paga la prima quota di prefinanziamento. Tale rimborso non incide in alcun modo sul contributo dell'Unione al programma operativo in questione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La liquidazione contabile dell'importo versato a titolo di prefinanziamento è effettuata integralmente dalla Commissione al più tardi al momento della chiusura del programma operativo.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Termini per la presentazione di domande di pagamenti intermedi e per il relativo pagamento", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità di certificazione trasmette regolarmente, a norma dell'articolo 41, paragrafo 2, una domanda di pagamento intermedio concernente gli importi contabilizzati nel periodo contabile nel sistema contabile di tale autorità. L'autorità di certificazione può tuttavia includere, ove lo ritenga necessario, tali importi nelle domande di pagamento presentate nei successivi periodi contabili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'autorità di certificazione trasmette la domanda finale di un pagamento intermedio entro il 31 luglio successivo alla chiusura del precedente periodo contabile e in ogni caso prima della prima domanda di pagamento intermedio per il successivo periodo contabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La prima domanda di pagamento intermedio non può essere presentata prima della notifica alla Commissione della designazione dell'autorità di gestione e dell'autorità di certificazione a norma dell'articolo 35.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Non sono effettuati pagamenti intermedi per un programma operativo salvo se la relazione di attuazione annuale è stata inviata alla Commissione conformemente all'articolo 13.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Compatibilmente con la disponibilità di fondi, la Commissione effettua il pagamento intermedio entro 60 giorni dalla data di registrazione presso la Commissione della domanda di pagamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M6\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, il termine per la trasmissione della domanda finale di un pagamento intermedio per il periodo contabile finale è il 31 luglio 2025. L'ultima domanda di pagamento intermedio trasmessa entro il 31 luglio 2025 è considerata la domanda finale di un pagamento intermedio per il periodo contabile finale.</div>\n</div>"], [null, "<p class=\"norm\">Gli importi rimborsati dalla Commissione a titolo di pagamenti intermedi nel 2025 non superano l'1 % delle dotazioni finanziarie complessive per il programma interessato. Gli importi dovuti dalla Commissione nel 2025 che superano tale percentuale non sono versati e sono utilizzati esclusivamente per la liquidazione del prefinanziamento alla chiusura.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "46": {"label": "Articolo 46", "heading": "Interruzione dei termini di pagamento", "anchor": "art_46", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I termini di pagamento di una richiesta di pagamento intermedio possono essere interrotti dall'ordinatore delegato ai sensi del regolamento finanziario per un periodo massimo di sei mesi nel caso in cui:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a seguito di informazioni fornite da un organismo di audit nazionale o dell'Unione, vi siano prove chiare che facciano presumere carenze significative nel funzionamento del sistema di gestione e controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'ordinatore delegato debba effettuare verifiche supplementari, essendo venuto a conoscenza della possibilità che le spese contenute in una richiesta di pagamento siano connesse a un'irregolarità con gravi conseguenze finanziarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sia stato presentato uno dei documenti richiesti ai sensi dell'articolo 59, paragrafo 5, del regolamento finanziario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri possono concedere un'estensione del periodo di interruzione di ulteriori tre mesi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'ordinatore delegato limita l'interruzione dei termini di pagamento a quella parte delle spese oggetto della richiesta di pagamento in cui si rinvengano gli elementi di cui al paragrafo 1, primo comma, salvo qualora non sia possibile identificare la parte delle spese interessate. L'ordinatore delegato informa immediatamente per iscritto lo Stato membro e l'autorità di gestione in merito ai motivi dell'interruzione, chiedendo a essi di porre rimedio alla situazione. L'ordinatore delegato pone fine all'interruzione non appena siano state adottate le misure necessarie.</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Sospensione dei pagamenti", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può sospendere la totalità o una parte dei pagamenti intermedi qualora si verifichino una o più delle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">vi siano gravi carenze nel funzionamento effettivo del sistema di gestione e controllo del programma operativo, che hanno messo a rischio il contributo dell'Unione al programma operativo e per le quali non sono state adottate misure correttive;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese figuranti in una dichiarazione di spesa siano connesse a un'irregolarità con gravi conseguenze finanziarie che non è stata rettificata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro non abbia adottato le azioni necessarie per porre rimedio alla situazione che ha dato origine a un'interruzione ai sensi dell'articolo 46;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sussistano gravi carenze nella qualità e nell'affidabilità del sistema di sorveglianza o dei dati sugli indicatori.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può decidere, mediante atti di esecuzione, di sospendere la totalità o una parte dei pagamenti intermedi dopo aver dato allo Stato membro la possibilità di presentare osservazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione pone fine alla sospensione della totalità o di una parte dei pagamenti intermedi se lo Stato membro ha adottato le misure necessarie per consentirne la revoca.</div>\n</div>"]]}, "48": {"label": "Articolo 48", "heading": "Presentazione di informazioni", "anchor": "art_48", "frags": [[null, "<p class=\"norm\">Per ogni esercizio, a decorrere dal 2016 e fino al 2025 compreso, gli Stati membri trasmettono alla Commissione entro il termine stabilito all'articolo 59, paragrafo 5, del regolamento finanziario, i seguenti documenti di cui a detto articolo, vale a dire:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i conti di cui all'articolo 49, paragrafo 1, del presente regolamento, per il precedente periodo contabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la dichiarazione di gestione e la relazione annuale di sintesi di cui all'articolo 29, paragrafo 4, lettera e), del presente regolamento, per il precedente periodo contabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il parere di audit e la relazione di controllo di cui all'articolo 34, paragrafo 5, lettere a) e b), del presente regolamento, per il precedente periodo contabile.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M6\n</p>"], [null, "<p class=\"norm\">In deroga al termine di cui al primo comma, gli Stati membri possono trasmettere i documenti di cui alle lettere a), b) e c) per il periodo contabile finale entro il 15 febbraio 2026.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "49": {"label": "Articolo 49", "heading": "Preparazione dei conti", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I conti di cui all'articolo 59, paragrafo 5, primo comma, lettera a), del regolamento finanziario sono presentati alla Commissione per ciascun programma operativo. I conti coprono il periodo contabile e comprendono i seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'importo totale di spese pubbliche ammissibili registrato dall'autorità di certificazione nei propri sistemi contabili, che è stato inserito in domande di pagamento presentate alla Commissione a norma dell'articolo 41 e dell'articolo 45, paragrafo 2, entro il 31 luglio successivo alla fine del periodo contabile, l'importo totale della spesa pubblica ammissibile corrispondente sostenuta per l'esecuzione delle operazioni e l'importo totale dei pagamenti corrispondenti effettuati ai beneficiari a norma dell'articolo 42, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi ritirati e recuperati nel corso del periodo contabile, gli importi da recuperare al termine del periodo contabile e gli importi non recuperabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un raffronto tra le spese dichiarate ai sensi della lettera a) e le spese dichiarate rispetto al medesimo periodo contabile nelle domande di pagamento, accompagnato da una spiegazione delle eventuali differenze.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora le spese previamente incluse in una domanda di pagamento intermedio per il periodo contabile siano escluse da uno Stato membro a causa di una valutazione in corso della legittimità e della regolarità di tali spese, parte o tutte le spese in seguito ritenute legittime e regolari possono essere incluse in una domanda di pagamento intermedio relativa a un successivo periodo contabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta atti di esecuzione stabilendo il modello dei conti di cui al presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d'esame di cui all'articolo 63, paragrafo 3.</div>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Esame e accettazione dei conti", "anchor": "art_50", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 31 maggio dell'anno successivo alla chiusura del periodo contabile, la Commissione procede, a norma dell'articolo 59, paragrafo 6, del regolamento finanziario, a un esame dei documenti presentati dagli Stati membri a norma dell'articolo 48 del presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Su richiesta della Commissione, lo Stato membro fornisce tutte le informazioni supplementari necessarie per consentire alla Commissione di accertare la completezza, l'accuratezza e la veridicità dei conti entro il termine fissato al primo comma del presente articolo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione accetta i conti ove sia in grado di accertarne la completezza, l'accuratezza e la veridicità. La Commissione raggiunge tale conclusione ove l'autorità di audit abbia fornito un parere di audit non qualificato riguardante la completezza, l'accuratezza e la veridicità dei conti, a meno che la Commissione non disponga di prove specifiche che dimostrino l'inaffidabilità del parere di audit sui conti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione comunica allo Stato membro se può accettare i conti entro il termine stabilito al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se per motivi addebitabili allo Stato membro non è in grado di accettare i conti entro il termine di cui al paragrafo 1, la Commissione comunica agli Stati membri le ragioni specifiche di cui al paragrafo 2 del presente articolo e le azioni che devono essere avviate e i termini per il loro completamento. Al termine di detto periodo la Commissione comunica allo Stato membro se è in grado di accettare i conti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ai fini dell'accettazione dei conti da parte della Commissione non si tiene conto di questioni connesse alla legittimità e alla regolarità delle operazioni sottostanti riguardanti le spese contabilizzate. La procedura di esame e accettazione dei conti non interrompe il trattamento delle domande di pagamento intermedio e non determina la sospensione dei pagamenti, fatti salvi gli articoli 46 e 47.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sulla base dei conti accettati, la Commissione calcola l'importo imputabile al Fondo per il periodo contabile e gli adeguamenti conseguenti in relazione ai pagamenti allo Stato membro. La Commissione tiene conto di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi contabilizzati di cui all'articolo 49, paragrafo 1, lettera a), e ai quali deve applicarsi il tasso di cofinanziamento definito all'articolo 20;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'ammontare totale dei pagamenti effettuati dalla Commissione durante il periodo contabile, costituiti dall'importo dei pagamenti intermedi effettuati dalla Commissione ai sensi dell'articolo 21 e dell'articolo 40, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">A seguito del calcolo effettuato a norma del paragrafo 6 del presente articolo, la Commissione versa l'eventuale importo aggiuntivo dovuto entro 30 giorni dall'accettazione dei conti. Qualora esista un importo recuperabile dallo Stato membro, tale importo è soggetto a un ordine di recupero emesso dalla Commissione, che è eseguito, ove possibile, mediante compensazione degli importi dovuti allo Stato membro nell'ambito di pagamenti successivi al medesimo programma operativo. Tale recupero non costituisce una rettifica finanziaria e non comporta una riduzione del contributo del Fondo al programma operativo. L'importo recuperato costituisce un'entrata con destinazione specifica conformemente all'articolo 177, paragrafo 3, del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Qualora, previa applicazione della procedura di cui al paragrafo 4, non sia in grado di accettare i conti, la Commissione stabilisce, sulla base delle informazioni disponibili e a norma del paragrafo 6, l'importo imputabile al Fondo per il periodo contabile e ne informa lo Stato membro. Se lo Stato membro notifica il suo accordo alla Commissione entro due mesi dalla trasmissione dell'informazione da parte della Commissione, si applica il paragrafo 7. In assenza di tale accordo, la Commissione adotta, mediante atti di esecuzione, una decisione che stabilisce l'importo imputabile al Fondo per il periodo contabile. Tale decisione non costituisce una rettifica finanziaria e non comporta una riduzione del contributo del Fondo al programma operativo. Sulla base di tale decisione, la Commissione applica gli adeguamenti dei pagamenti allo Stato membro conformemente al paragrafo 7.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">L'accettazione dei conti da parte della Commissione o una decisione da parte della Commissione a norma del paragrafo 8 lascia impregiudicata l'applicazione delle rettifiche a norma degli articoli 55 e 56.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono sostituire gli importi irregolari individuati dopo la presentazione dei conti effettuando gli adeguamenti corrispondenti nei conti relativi al periodo contabile in cui è individuata l'irregolarità, fatti salvi gli articoli 55 e 56.</div>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Disponibilità dei documenti", "anchor": "art_51", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione assicura che tutti i documenti giustificativi relativi alle spese sostenute dal Fondo per operazioni per le quali la spesa pubblica totale ammissibile è inferiore a 1 000 000  EUR siano resi disponibili su richiesta alla Commissione e alla Corte dei conti europea per un periodo di tre anni a decorrere dal 31 dicembre successivo alla presentazione dei conti nei quali sono incluse le spese dell'operazione.</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di operazioni diverse da quelle di cui al primo comma, tutti i documenti giustificativi sono resi disponibili per un periodo di due anni a decorrere dal 31 dicembre successivo alla presentazione dei conti nei quali sono incluse le spese finali dell'operazione completata.</p>"], [null, "<p class=\"norm\">Un'autorità di gestione può decidere di applicare alle operazioni con spese ammissibili per un totale inferiore a 1 000 000  EUR la norma di cui al secondo comma.</p>"], [null, "<p class=\"norm\">Il periodo di tempo di cui al primo comma è interrotto in caso di procedimento giudiziario o su richiesta debitamente motivata della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'autorità di gestione informa i beneficiari della data di inizio del periodo di cui al paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I documenti sono conservati sotto forma di originali o di copie autenticate, o su supporti per i dati comunemente accettati, comprese le versioni elettroniche di documenti originali o i documenti esistenti esclusivamente in versione elettronica. Se i documenti sono conservati su supporti per i dati comunemente accettati in conformità della procedura di cui al paragrafo 5, gli originali non sono necessari.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I documenti sono conservati in una forma tale da consentire l'identificazione delle persone interessate solo per il periodo necessario al conseguimento delle finalità per le quali i dati sono rilevati o successivamente trattati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La procedura per la certificazione della conformità dei documenti conservati su supporti comunemente accettati al documento originale è stabilita dalle autorità nazionali e garantisce che le versioni conservate rispettino i requisiti giuridici nazionali e siano affidabili ai fini dell'attività di audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Laddove i documenti siano disponibili esclusivamente in formato elettronico, i sistemi informatici utilizzati soddisfano gli standard di sicurezza accettati, che garantiscono che i documenti conservati rispettino i requisiti giuridici nazionali e siano affidabili ai fini dell'attività di audit.</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Presentazione dei documenti di chiusura e pagamento del saldo finale", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Oltre ai documenti di cui all'articolo 48, per il periodo contabile dal 1<span class=\"superscript\">o</span> luglio 2023 al 30 giugno 2024 gli Stati membri presentano la relazione di attuazione finale del programma operativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il pagamento del saldo finale avviene entro tre mesi dalla data di accettazione dei conti del periodo contabile finale o entro un mese dalla data di accettazione della relazione di attuazione finale, se successiva.</div>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Rettifiche finanziarie effettuate dagli Stati membri", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Spetta anzitutto agli Stati membri fare accertamenti sulle irregolarità, effettuare le rettifiche finanziarie necessarie e procedere ai recuperi. Nel caso di un'irregolarità sistemica, lo Stato membro estende le proprie indagini a tutte le operazioni che potrebbero essere interessate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro procede alle rettifiche finanziarie necessarie in relazione alle irregolarità isolate o sistemiche individuate nell'ambito di operazioni o programmi operativi. Le rettifiche finanziarie consistono in una soppressione totale o parziale del contributo pubblico a un'operazione o programma operativo. Lo Stato membro tiene conto della natura e della gravità delle irregolarità e della perdita finanziaria che ne risulta per il Fondo e apporta una rettifica proporzionale. L'autorità di gestione inserisce le rettifiche nei bilanci del periodo contabile nel quale è decisa la soppressione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il contributo a titolo del Fondo soppresso a norma del paragrafo 2 può essere reimpiegato dallo Stato membro nell'ambito del programma operativo in questione, alle condizioni di cui al paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il contributo soppresso a norma del paragrafo 2 non può essere reimpiegato per le operazioni oggetto di rettifica o, laddove la rettifica finanziaria riguardi una irregolarità sistemica, per le operazioni interessate da tale irregolarità sistemica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Una rettifica finanziaria non pregiudica l'obbligo degli Stati membri di proseguire nei recuperi ai sensi del presente articolo.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Rettifiche finanziarie effettuate dalla Commissione", "anchor": "art_54", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione procede, mediante un atto di esecuzione, a rettifiche finanziarie sopprimendo in tutto o in parte il contributo dell'Unione a un programma operativo e procedendo al recupero presso lo Stato membro al fine di escludere le spese che violano il diritto applicabile dal finanziamento dell'Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Una violazione del diritto applicabile determina una rettifica finanziaria solo se riguarda una spesa che è stata notificata alla Commissione e ove una delle seguenti condizioni sia soddisfatta:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la violazione ha influenzato la selezione di un'operazione da parte dell'organismo responsabile di un'operazione ammessa al sostegno del Fondo o in casi in cui, date le caratteristiche della violazione, non risulti possibile accertarne l'incidenza ma sussista un rischio sostanziale che la violazione in questione abbia avuto tale effetto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la violazione ha influenzato l'importo delle spese dichiarate per il rimborso a carico del bilancio dell'Unione o in casi in cui, date le caratteristiche della violazione, non risulti possibile quantificarne l'incidenza finanziaria ma sussista il rischio sostanziale che la violazione in questione abbia avuto tale effetto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nel decidere una rettifica finanziaria ai sensi del paragrafo 1, la Commissione rispetta il principio di proporzionalità tenendo conto della natura e della gravità della violazione del diritto applicabile e delle sue implicazioni finanziarie per il bilancio dell'Unione. La Commissione tiene aggiornato il Parlamento europeo e il Consiglio sulle decisioni adottate per l'applicazione delle rettifiche finanziarie.</div>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Criteri per le rettifiche finanziarie della Commissione", "anchor": "art_55", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione procede a rettifiche finanziarie mediante atti di esecuzione, sopprimendo in tutto o in parte il contributo dell'Unione a un programma operativo a norma dell'articolo 54, qualora, effettuate le necessarie verifiche, essa concluda che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">vi è una grave carenza nell'efficace funzionamento del sistema di gestione e di controllo del programma operativo, tale da compromettere il contributo dell'Unione già versato al programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro non si è conformato agli obblighi che gli incombono a norma dell'articolo 53 anteriormente all'avvio della procedura di rettifica ai sensi del presente paragrafo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese figuranti in una domanda di pagamento sono irregolari e non sono state rettificate dallo Stato membro anteriormente all'avvio della procedura di rettifica ai sensi del presente paragrafo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione basa le proprie rettifiche finanziarie su singoli casi di irregolarità individuati, valutando se si tratta di un'irregolarità sistemica. Qualora non sia possibile quantificare con precisione l'importo di spesa irregolare addebitato al Fondo, la Commissione applica una rettifica finanziaria su base forfettaria o per estrapolazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel decidere una rettifica ai sensi del paragrafo 1, la Commissione si attiene al principio di proporzionalità, tenendo conto della natura e della gravità dell'irregolarità, nonché della portata e delle implicazioni finanziarie delle carenze dei sistemi di gestione e controllo riscontrate nel programma operativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ove si basi su relazioni di revisori non appartenenti ai propri servizi, la Commissione trae le proprie conclusioni circa le conseguenze finanziarie dopo aver esaminato le misure adottate dallo Stato membro interessato a norma dell'articolo 53, paragrafo 2, le notifiche inviate a norma dell'articolo 30, paragrafo 2, e le eventuali risposte dello Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 62 riguardo alle norme dettagliate relative ai criteri per determinare carenze gravi nell'efficace funzionamento dei sistemi di gestione e controllo, tra cui le principali fattispecie di tali carenze, i criteri per stabilire il livello di rettifica finanziaria da applicare e i criteri per applicare i tassi forfettari o le rettifiche finanziarie estrapolate.</div>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Procedura per le rettifiche finanziarie della Commissione", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima di decidere in merito a una rettifica finanziaria, la Commissione avvia la procedura comunicando allo Stato membro le conclusioni provvisorie del suo esame e invitandolo a trasmettere osservazioni entro un termine di due mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se la Commissione propone una rettifica finanziaria calcolata per estrapolazione o su base forfettaria, è data la possibilità allo Stato membro di dimostrare, attraverso un esame della documentazione pertinente, che la portata reale delle irregolarità è inferiore alla valutazione della Commissione. D'intesa con la Commissione, lo Stato membro può limitare l'ambito di tale esame a una parte o a un campione adeguati della documentazione di cui trattasi. Tranne in casi debitamente giustificati, il termine concesso per l'esecuzione dell'esame è limitato a un periodo ulteriore di due mesi successivi al periodo di due mesi di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione tiene conto di ogni prova eventualmente fornita dallo Stato membro entro i termini di cui ai paragrafi 1 e 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se non accetta le conclusioni provvisorie della Commissione, lo Stato membro è da questa convocato per un'audizione, in modo che tutte le informazioni e osservazioni pertinenti siano a disposizione della Commissione ai fini delle conclusioni in merito all'applicazione della rettifica finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di accordo e fatto salvo il paragrafo 7 del presente articolo, lo Stato membro può riutilizzare il Fondo conformemente all'articolo 53, paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Per applicare le rettifiche finanziarie la Commissione adotta una decisione, mediante atti di esecuzione, entro sei mesi dalla data dell'audizione, o dalla data di ricevimento di informazioni aggiuntive, ove lo Stato membro convenga di presentarle successivamente all'audizione. La Commissione tiene conto di tutte le informazioni fornite e delle osservazioni formulate durante la procedura. Se l'audizione non ha luogo, il termine di sei mesi decorre da due mesi dopo la data della lettera di convocazione per l'audizione trasmessa dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se la Commissione, nell'espletamento delle sue responsabilità di cui all'articolo 36, o la Corte dei conti europea rilevano irregolarità che dimostrino una carenza grave nell'efficace funzionamento dei sistemi di gestione e controllo, le conseguenti rettifiche finanziarie riducono il sostegno del Fondo al programma operativo.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il primo comma non si applica in caso di carenze gravi nell'efficace funzionamento del sistema di gestione e controllo che, prima della data di accertamento da parte della Commissione o della Corte dei conti europea:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano state individuate nella dichiarazione di gestione, nella relazione annuale di controllo o nel parere di audit presentati alla Commissione a norma dell'articolo 59, paragrafo 5, del regolamento finanziario o in altre relazioni di audit dell'autorità di audit presentate alla Commissione e siano state oggetto di interventi appropriati; oppure</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano state oggetto di adeguate misure correttive da parte dello Stato membro.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La valutazione delle gravi carenze nell'efficace funzionamento dei sistemi di gestione e controllo è basata sul diritto applicabile al momento della presentazione delle dichiarazioni di gestione, delle relazioni annuali di controllo e dei pareri di audit pertinenti.</p>"], [null, "<p class=\"norm inline-element\">Nel decidere su una rettifica finanziaria la Commissione:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispetta il principio di proporzionalità tenendo conto della natura e della gravità della carenza grave nell'efficace funzionamento dei sistemi di gestione e controllo e delle relative implicazioni finanziarie per il bilancio dell'Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai fini dell'applicazione di una rettifica su base forfettaria o per estrapolazione, esclude le spese irregolari precedentemente rilevate dallo Stato membro che sono state oggetto di adeguamento dei conti conformemente all'articolo 50, paragrafo 10, e le spese oggetto di valutazione in corso della loro legittimità e regolarità a norma dell'articolo 49, paragrafo 2;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tiene conto delle rettifiche su base forfettaria o per estrapolazione applicate alle spese dallo Stato membro per altre carenze gravi rilevati dallo Stato membro al momento di determinare il rischio residuo per il bilancio dell'Unione.</p>\n</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Rimborso", "anchor": "art_57", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualsiasi importo dovuto al bilancio dell'Unione è rimborsato entro il termine indicato nell'ordine di riscossione emesso a norma dell'articolo 73 del regolamento finanziario. Detto termine corrisponde all'ultimo giorno del secondo mese successivo all'emissione dell'ordine.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni ritardo nel provvedere al rimborso dà luogo all'applicazione di interessi di mora, a decorrere dalla data di scadenza del termine e fino alla data del pagamento effettivo. Il tasso di tale interesse è superiore di un punto e mezzo percentuale rispetto al tasso applicato dalla Banca centrale europea alle sue principali operazioni di rifinanziamento il primo giorno lavorativo del mese in cui scade il termine.</div>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Proporzionalità in materia di controllo dei programmi operativi", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le operazioni per le quali la spesa totale ammissibile non supera 150 000  EUR non sono soggette a più di un audit da parte dell'autorità di audit o della Commissione prima della presentazione dei bilanci in cui sono incluse le spese finali dell'operazione completata. Altre operazioni non sono soggette a più di un audit per periodo contabile da parte dell'autorità di audit o della Commissione prima della presentazione dei bilanci in cui sono incluse le spese finali dell'operazione completata. Le operazioni non sono soggette a un audit da parte della Commissione o dell'autorità di audit in qualsiasi anno, se è già stato svolto un audit durante quello stesso anno, da parte della Corte dei conti europea, posto che i risultati dei lavori di audit eseguiti dalla Corte dei conti europea per tali operazioni possano essere utilizzati dall'autorità di audit o dalla Commissione al fine di ottemperare ai loro rispettivi compiti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'audit di un'operazione sostenuta da un PO I può riguardare tutte le fasi della sua attuazione e tutti i livelli della catena di distribuzione, con la sola eccezione del controllo dei destinatari finali, a meno che una valutazione dei rischi indichi un rischio specifico di irregolarità o frodi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Riguardo ai programmi operativi per i quali il parere di audit più recente non segnala l'esistenza di carenze significative, la Commissione può concordare con l'autorità di audit nel successivo incontro di cui all'articolo 37, paragrafo 2, che il livello di audit richiesto può essere ridotto in misura proporzionale al rischio individuato. In tal caso, la Commissione svolge audit sul posto per proprio conto solo qualora vi siano prove che facciano presumere carenze nel sistema di gestione e controllo che incidono sulle spese dichiarate alla Commissione in un periodo contabile i cui bilanci sono stati oggetto di una decisione di accettazione da parte della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Riguardo ai programmi operativi per i quali la Commissione conclude che il parere dell'autorità di audit è affidabile, può concordare con la stessa di limitare gli audit sul posto della Commissione alla verifica dell'operato dell'autorità di audit, a meno che vi siano prove che facciano presumere carenze nell'operato dell'autorità di audit per un periodo contabile i cui bilanci sono stati accettati dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, l'autorità di audit e la Commissione possono effettuare audit relativi alle operazioni qualora da una valutazione del rischio o da un audit effettuato dalla Corte dei conti europea emerga un rischio specifico di irregolarità o di frode, qualora vi siano prove che facciano presumere gravi carenze nell'efficace funzionamento del sistema di gestione e controllo del programma operativo interessato e durante il periodo di cui all'articolo 51, paragrafo 1. La Commissione può, al fine di valutare il lavoro di un'autorità di audit, esaminare la pista di controllo dell'autorità di audit o partecipare ai controlli sul posto dell'autorità di audit e può, ove necessario, conformemente agli standard internazionalmente riconosciuti, allo scopo di ottenere garanzie in merito all'efficace funzionamento dell'autorità di audit, effettuare audit relativi alle operazioni.</div>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Disimpegno", "anchor": "art_59", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione procede al disimpegno della parte dell'importo in un programma operativo che non sia stata utilizzata per il pagamento del prefinanziamento e per i pagamenti intermedi entro il 31 dicembre del terzo esercizio successivo a quello dell'impegno di bilancio nell'ambito del programma operativo, o per la quale non sia stata presentata, a norma dell'articolo 45, una domanda di pagamento redatta a norma dell'articolo 41, compresa qualsiasi domanda di pagamento interamente o parzialmente soggetta a una interruzione dei termini di pagamento o alla sospensione dei pagamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La parte di impegni ancora aperti al 31 dicembre 2023 è disimpegnata qualora la Commissione non abbia ricevuto i documenti prescritti ai sensi dell'articolo 52, paragrafo 1, entro il termine stabilito all'articolo 52, paragrafo 1.</div>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Eccezioni al disimpegno", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'importo interessato dal disimpegno si intende ridotto degli importi equivalenti alla parte dell'impegno di bilancio per la quale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le operazioni sono sospese in virtù di un procedimento giudiziario o di un ricorso amministrativo con effetto sospensivo; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non è stato possibile eseguire una richiesta di pagamento per cause di forza maggiore che compromettono gravemente l'attuazione del programma operativo, in tutto o in parte.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le autorità nazionali che invocano la forza maggiore di cui al primo comma, lettera b), ne dimostrano le conseguenze dirette sulla realizzazione di tutto o parte del programma operativo.</p>"], [null, "<p class=\"norm\">Ai fini del primo comma, lettere a) e b), la riduzione può essere richiesta una volta se la sospensione o la situazione di forza maggiore sono durate non più di un anno, o un numero di volte che corrisponde alla durata della situazione di forza maggiore o al numero di anni compresi tra la data della decisione giudiziaria o amministrativa che sospende l'esecuzione dell'operazione e la data della decisione finale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 31 gennaio lo Stato membro invia alla Commissione informazioni in merito alle eccezioni di cui al paragrafo 1, primo comma, lettere a) e b), per l'importo da dichiarare entro la chiusura dell'esercizio precedente.</div>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Procedura", "anchor": "art_61", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione informa in tempo utile lo Stato membro e l'autorità di gestione ogniqualvolta esista un rischio di applicazione della norma sul disimpegno ai sensi dell'articolo 59.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Sulla base delle informazioni che ha ricevuto al 31 gennaio, la Commissione informa lo Stato membro e l'autorità di gestione circa l'importo del disimpegno risultante da dette informazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro dispone di due mesi per accettare l'importo oggetto del disimpegno o per trasmettere osservazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Entro il 30 giugno lo Stato membro presenta alla Commissione un piano finanziario modificato che riflette, per l'esercizio interessato, la riduzione del contributo relativo al programma operativo. In caso di mancata presentazione la Commissione modifica il piano finanziario riducendo il contributo del Fondo per l'esercizio interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione modifica la decisione che adotta il programma operativo, mediante atti di esecuzione, entro il 30 settembre.</div>\n</div>"]]}, "62": {"label": "Articolo 62", "heading": "Esercizio della delega", "anchor": "art_62", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all'articolo 13, paragrafo 6, all'articolo 30, paragrafo 2, quinto comma, all'articolo 32, paragrafi 8 e 9, all'articolo 34 paragrafi 7 e 8 e all'articolo 55, paragrafo 4, è conferito alla Commissione per un periodo indeterminato a decorrere dalla data di entrata in vigore dello stesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'atto delegato entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"], [null, "<p class=\"norm\">Se, alla scadenza di tale termine, né Parlamento europeo né il Consiglio hanno sollevato obiezioni all'atto delegato, quest'ultimo è pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span> ed entra in vigore alla data in esso indicata.</p>"], [null, "<p class=\"norm\">L'atto delegato può essere pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europe</span>a ed entrare in vigore prima della scadenza di tale termine se il Parlamento europeo e il Consiglio hanno entrambi informato la Commissione che non intendono sollevare obiezioni.</p>"], [null, "<p class=\"norm\">Se il Parlamento europeo o il Consiglio sollevano obiezioni, l'atto delegato non entra in vigore. L'istituzione che solleva obiezioni le motiva.</p>"]]}, "63": {"label": "Articolo 63", "heading": "Procedura di comitato", "anchor": "art_63", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 4 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"norm\">Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione relativamente ai poteri di esecuzione di cui all'articolo 32, paragrafo 8, secondo comma del presente regolamento, e si applica l'articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</p>"]]}, "63a": {"label": "Articolo 63 bis", "heading": "Applicabilità", "anchor": "art_63a", "frags": [[null, "<p class=\"norm\">L’articolo 6 <span class=\"italics\">bis</span> non si applica al Regno Unito o nel Regno Unito. I riferimenti agli Stati membri contenuti in tale articolo non si intendono fatti al Regno Unito.</p>"]]}, "64": {"label": "Articolo 64", "heading": "Entrata in vigore", "anchor": "art_64", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno della pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell'Unione europea</span>. Esso si applica a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2014.</p>"]]}}, "recitals": {}};